/**
 * @ch Respin 雙層索引純邏輯層自動化測試
 * 對象：assets/Script/Respin/RespinPlateLogic.ts（零 cc 依賴，可在 Node 跑）
 * 執行：npx ts-node -O '{"module":"commonjs"}' --transpile-only tests/RespinPlateLogic.test.ts
 * 涵蓋：[testable] BC-1（旗標投影）, BC-2（雙層推進軌跡）, BC-3（鎖定解碼 fail-loud）
 */

import {
    AdvancePlateCursorPure,
    IsGoingToFreePure,
    IsGoingToRespinPure,
    ResolveLockedEntries,
} from '../assets/Script/Respin/RespinPlateLogic';

let total = 0;
let passed = 0;
const failures: string[] = [];

function check( name: string, cond: boolean ): void
{
    total++;
    if ( cond )
    {
        passed++;
    }
    else
    {
        failures.push( name );
        console.error( `  ✗ ${name}` );
    }
}

function eq( name: string, actual: unknown, expected: unknown ): void
{
    check( `${name}（得 ${JSON.stringify( actual )}，期 ${JSON.stringify( expected )}）`,
        JSON.stringify( actual ) === JSON.stringify( expected ) );
}

// ============================================================
// BC-1：旗標投影語意
// ============================================================
console.log( '— BC-1 IsGoingToFreePure —' );
eq( 'MG 首局多 round 未進 FG → true', IsGoingToFreePure( 0, 2, false ), true );
eq( 'FG 進行中（isFreeGame）→ false', IsGoingToFreePure( 0, 2, true ), false );
eq( '單局（len=1）→ false', IsGoingToFreePure( 0, 1, false ), false );
eq( '非首局 round=1 → false', IsGoingToFreePure( 1, 3, false ), false );
eq( 'FG 結束 round=last → false', IsGoingToFreePure( 4, 5, false ), false );
eq( '閒置 round=-1 → false', IsGoingToFreePure( -1, 0, false ), false );

console.log( '— BC-1 IsGoingToRespinPure —' );
eq( 'sub<plateCount-1 → true', IsGoingToRespinPure( 0, 3 ), true );
eq( '中間手 sub=1/3 → true', IsGoingToRespinPure( 1, 3 ), true );
eq( '末手 sub=2/3 → false', IsGoingToRespinPure( 2, 3 ), false );
eq( '單 plate（plateCount=1）→ false', IsGoingToRespinPure( 0, 1 ), false );
eq( 'plateCount=0（缺值）→ false', IsGoingToRespinPure( 0, 0 ), false );
eq( 'plateCount=-1（異常）→ false', IsGoingToRespinPure( 0, -1 ), false );

// ============================================================
// BC-2：雙層推進軌跡
// RoundQueue 形狀 [{plates:3},{plates:1},{plates:2}]
// 自 (-1,0) 連續 Advance 必為 (0,0)→(0,1)→(0,2)→(1,0)→(2,0)→(2,1)→(3,0)
// ============================================================
console.log( '— BC-2 雙層推進軌跡 —' );
{
    const plates = [ 3, 1, 2 ];
    // 取「當前 round 對應」的 plateCount：round 無效（<0 或越界）→ 0
    const plateCountOf = ( round: number ): number =>
        ( round >= 0 && round < plates.length ) ? plates[ round ] : 0;

    const trajectory: Array<{ round: number; sub: number }> = [];
    let cur = { round: -1, sub: 0 };
    for ( let i = 0; i < 7; i++ )
    {
        cur = AdvancePlateCursorPure( cur.round, cur.sub, plateCountOf( cur.round ) );
        trajectory.push( cur );
    }
    eq( '軌跡', trajectory, [
        { round: 0, sub: 0 },
        { round: 0, sub: 1 },
        { round: 0, sub: 2 },
        { round: 1, sub: 0 },
        { round: 2, sub: 0 },
        { round: 2, sub: 1 },
        { round: 3, sub: 0 },
    ] );
}
// 單 plate 退化：每次 advance 都換局
eq( '單 plate 退化 (0,0)+count1 → (1,0)', AdvancePlateCursorPure( 0, 0, 1 ), { round: 1, sub: 0 } );
// 連鎖 plates≥3：中間手只推 sub
eq( '連鎖 (0,1)+count4 → (0,2)', AdvancePlateCursorPure( 0, 1, 4 ), { round: 0, sub: 2 } );
eq( '連鎖末手 (0,3)+count4 → (1,0)', AdvancePlateCursorPure( 0, 3, 4 ), { round: 1, sub: 0 } );
// 從 idle (-1,0) plateCount=0 → (0,0)
eq( 'idle (-1,0)+count0 → (0,0)', AdvancePlateCursorPure( -1, 0, 0 ), { round: 0, sub: 0 } );

// ============================================================
// BC-3：ResolveLockedEntries fail-loud
// ============================================================
console.log( '— BC-3 ResolveLockedEntries —' );
{
    // 假解碼器：serverPos 直接編碼 col*10+row，負數視為無法解碼
    const decode = ( p: number ): { col: number; row: number } | null =>
        p < 0 ? null : { col: Math.floor( p / 10 ), row: p % 10 };

    // 正常盤面：col1 row0 = Cash(14) number 100、col2 row1 = Mystery(20) number 0
    const plate = [
        { Col: [ { Symbol: 0, Number: 0 } ] },                       // col0
        { Col: [ { Symbol: 14, Number: 100 } ] },                    // col1: (10) → Cash
        { Col: [ { Symbol: 0, Number: 0 }, { Symbol: 20, Number: 0 } ] }, // col2: (21) → Mystery
    ];

    const r1 = ResolveLockedEntries( plate, [ 10, 21 ], decode );
    eq( '正常解碼 2 筆', r1.entries, [
        { serverPos: 10, col: 1, row: 0, symbol: 14, number: 100 },
        { serverPos: 21, col: 2, row: 1, symbol: 20, number: 0 },
    ] );
    eq( '正常無 warning', r1.warnings.length, 0 );

    // 空陣列 → 空 entries 無 warning
    const r2 = ResolveLockedEntries( plate, [], decode );
    eq( '空 serverPos → 空 entries', r2.entries.length, 0 );
    eq( '空 serverPos → 無 warning', r2.warnings.length, 0 );

    // null serverPositions → 空，不 throw
    const r3 = ResolveLockedEntries( plate, null, decode );
    eq( 'null serverPos → 空 entries', r3.entries.length, 0 );

    // 解碼失敗（負數）→ 跳該筆 + warning
    const r4 = ResolveLockedEntries( plate, [ -1, 10 ], decode );
    eq( '解碼失敗跳過、保留有效', r4.entries.length, 1 );
    check( '解碼失敗有 warning', r4.warnings.length === 1 );

    // col 越界 → 跳該筆 + warning，不 throw
    const r5 = ResolveLockedEntries( plate, [ 90 ], decode ); // col9 不存在
    eq( 'col 越界 → 空 entries', r5.entries.length, 0 );
    check( 'col 越界有 warning', r5.warnings.length === 1 );

    // row 越界（col1 只有 row0）→ 跳該筆 + warning
    const r6 = ResolveLockedEntries( plate, [ 15 ], decode ); // col1 row5 不存在
    eq( 'row 越界 → 空 entries', r6.entries.length, 0 );
    check( 'row 越界有 warning', r6.warnings.length === 1 );

    // Number 缺值 → 回 -1
    const plateNoNum = [ { Col: [ { Symbol: 14 } ] } ]; // col0 row0 Symbol 但無 Number
    const r7 = ResolveLockedEntries( plateNoNum, [ 0 ], decode );
    eq( 'Number 缺值回 -1', r7.entries, [ { serverPos: 0, col: 0, row: 0, symbol: 14, number: -1 } ] );

    // 不 throw：plateSymbol 為 null
    let threw = false;
    try { ResolveLockedEntries( null, [ 0 ], decode ); } catch { threw = true; }
    check( 'plateSymbol null 不 throw', !threw );
}

// ============================================================
console.log( `\n${passed}/${total} passed` );
if ( failures.length > 0 )
{
    console.error( `\n${failures.length} FAILED:` );
    failures.forEach( f => console.error( `  - ${f}` ) );
    process.exit( 1 );
}
console.log( '✅ all passed' );

