import { _decorator } from "cc";
import GameView from "../GameView";
import { log } from "cc";
import { BaseState, eventManager, stateManager } from "db://astarte-framework/Managers";
import Game_Define from "../Game_Define";
import { RESPIN_UI_EVENT } from "../Respin/RespinUIManager";
import { Common } from "../Common/Common";
import { Define, CommonState } from "db://astarte-framework/utilis";
import { ResolveLockedEntries } from "../Respin/RespinPlateLogic";

const { ccclass } = _decorator;

@ccclass( "EnterRespinState" )
export class EnterRespinState extends BaseState
{
    private m_gameView: GameView = null;

    /**@ch 首手進場等待時間（秒） */
    private static readonly WAIT_TIME = 0.8;

    /**@ch 宣告動畫開關（預留接縫）：預設不播；連首手都不播。
     * 未來若要恢復「首手播 Respin 宣告動畫」，改為 true 即可（續轉手一律不播）。 */
    private static readonly PLAY_ENTER_ANIM: boolean = false;

    /**@ch col 0/5 靜態張排除開關：true=重建靜態圖時跳過 col 0/5（RespinLockColumns）。
     * 這兩列已由 SetColumnLock 整輪鎖定（reel 不轉、原符號自然留存），毋須 EffectPlate 再疊靜態張。
     * server 改為 RespinLockedPos 含 col 0/5 後集合會帶這兩列 entry，故以此開關控制是否略過顯示處理。
     * 設 false 則回復「對集合內所有 entry（含 col 0/5）都疊靜態張」的舊行為。 */
    private static readonly EXCLUDE_LOCK_COLUMNS_FROM_STATIC: boolean = true;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        console.log( "OnEnter State: ENTER_RESPIN" );

        // 首手 / 續轉分流：首手時 IsRespinGame 尚未設為 true
        const isFirstHand = !this.m_gameView.IsRespinGame;

        if ( isFirstHand )
        {
            // 首手進場：緩衝等待 → 設 Respin 狀態 → 清盤（鎖列在 HandleReel 內處理）
            await Define.Wait( this.m_gameView, EnterRespinState.WAIT_TIME );
            this.m_gameView.IsRespinGame = true;
            this.m_gameView.ClearAll();
        }

        // 累加本手鎖定位置 + 以累積集合冪等重建靜態圖（首手與續轉同邏輯）
        this.HandleReel();

        // 宣告動畫：可開關，僅首手且開關開啟時播（預設不播，續轉手一律不播）
        if ( isFirstHand && EnterRespinState.PLAY_ENTER_ANIM )
        {
            await this.PlayRespinEnterAnimation();
        }

        // 去向改 SPIN（v2 骨架）：plate 內循環繞過 ROUND_END，續轉播下一手 plate；
        // 整局 plate 用盡後由 CheckState ② 走 LEAVE_RESPIN → ROUND_END（RoundInfo 級一次）
        stateManager.NextState( CommonState.SPIN );
    }

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }

    /**
     * @ch 處理轉輪鎖定：col 0/5 整輪鎖 + 累加 server 給定的鎖定位置，並冪等重建靜態圖
     *
     * 鎖定位置來源 = 「剛播完那手」PlateInfo.RespinLockedPos（server 給的增量 serverPos[]，含 col 0/5）。
     * ENTER_RESPIN 在 SPIN 推進 sub 之前執行，故 CurSubPlateIndex 仍指向剛播完的 plate。
     */
    private HandleReel(): void
    {
        // col 0/5 整輪鎖定（固定規則）：reel 不轉、原符號自然留存，視覺鎖定不靠 EffectPlate 靜態張
        Game_Define.RespinLockColumns.forEach( column => {
            this.m_gameView.SlotReels.SetColumnLock( column, true );
        } );

        // 讀「剛播完那手」的鎖定位置（server 增量），解碼後累加進 GameView 累積集合
        const plate = this.m_gameView.RoundInfo?.PlateQueue?.[ this.m_gameView.CurSubPlateIndex ];
        const { entries, warnings } = ResolveLockedEntries(
            plate?.PlateSymbol,
            plate?.RespinLockedPos,
            Common.DecodeServerPosByRowConfig
        );
        warnings.forEach( w => console.warn( `[EnterRespinState] ${w}` ) );
        this.m_gameView.MergeRespinLocks( entries );

        // 以「累積集合」全量冪等重建靜態圖——續轉手不依賴前一手演出殘留，可重入
        this.m_gameView.RespinLockedSet.forEach( entry =>
        {
            const { col, row, symbol, number } = entry;

            // col 0/5 已由 SetColumnLock 整輪鎖定（符號留存）；開關開啟時略過 EffectPlate 靜態張重建
            if ( EnterRespinState.EXCLUDE_LOCK_COLUMNS_FROM_STATIC
                && Game_Define.RespinLockColumns.includes( col ) )
            {
                return;
            }

            // CollectAndRetrigger 在 Respin 鎖定時顯示為 Collect 靜態張
            const displaySymbol = ( symbol === Game_Define.Symbol.CollectAndRetrigger )
                ? Game_Define.Symbol.Collect
                : symbol;

            // 清掉該位置殘留的 Spine 節點（停輪時建立的），避免蓋住靜態張
            this.m_gameView.EffectPlate.CleanSymbolSpineAt( col, row, Game_Define.LAYERS.TWO, false );

            // 關閉原本格子的靜態圖，改用 EffectPlate 疊一張靜態圖
            this.m_gameView.SlotReels.AllColumns?.[ Game_Define.MIDDLE_PLATE_INDEX ]?.[ col ]?.HideSymbolByRow( row );
            this.m_gameView.EffectPlate.CreateSymbolStaticNode( col, row, displaySymbol, number );
        } );
    }

    /**
     * @ch 播放 Respin 進入動畫
     */
    private async PlayRespinEnterAnimation(): Promise<void>
    {
        log( "=== PlayRespinEnterAnimation ===" );

        await new Promise<void>((resolve) => {
            eventManager.Dispatch(RESPIN_UI_EVENT.PLAY_RESPI_DECLARE_ANIM, () => {
                log("Respin 宣告動畫播放完成");
                resolve();
            });
        });
    }
}

