1	/**
2	 * @ch Respin 雙層索引純邏輯層（零 cc 依賴，可在 Node 跑）
3	 *
4	 * 為什麼獨立成檔：觸及 stateManager/GameView 的邏輯無既有自動化測試手段，
5	 * 把可測的判斷（游標推進 / 旗標投影 / 鎖定位置解碼）收進零依賴模組，
6	 * 是專案內唯一能放自動化測試的位置（對應 BC-1/2/3/9）。
7	 *
8	 * 設計原則：常數與解碼器一律由呼叫端「參數注入」，本模組不 import 任何
9	 * Cocos / Game_Define / Common，保持純函式可測。
10	 */
11	
12	/**
13	 * @ch 雙層游標推進
14	 *
15	 * 規則：當前 round 內還有未播 plate（sub < plateCount-1）→ 只推 sub、round 不動；
16	 *       否則（當前 round 的 plate 已播完）→ round+1、sub 歸 0。
17	 *
18	 * 邊界：呼叫端在 round 無效（如 -1，剛 Reset）時傳 plateCount=0，
19	 *       則 0 < 0-1 不成立 → 走換局分支 round+1=0、sub=0（從 idle 進第一局）。
20	 *
21	 * @param round      當前局索引（CurPlateIndex）
22	 * @param sub        當前局內 plate 索引（CurSubPlateIndex）
23	 * @param plateCount 當前局（round 對應）的 PlateQueue.length；取不到傳 0
24	 */
25	export function AdvancePlateCursorPure(
26	    round: number,
27	    sub: number,
28	    plateCount: number
29	): { round: number; sub: number }
30	{
31	    if ( sub < plateCount - 1 )
32	    {
33	        return { round, sub: sub + 1 };
34	    }
35	    return { round: round + 1, sub: 0 };
36	}
37	
38	/**
39	 * @ch IsGoingToFree 投影
40	 *
41	 * 語意：目前在 MainGame 局（round===0）且整包有多個 RoundInfo（觸發 FG）且尚未進 FG。
42	 * FG 進行中（isFreeGame=true）或非首局（round≠0）或單局（len≤1）皆為 false。
43	 *
44	 * @param round         當前局索引（CurPlateIndex）
45	 * @param roundQueueLen SpinAck.RoundQueue.length（缺值傳 0）
46	 * @param isFreeGame    GameView.IsFreeGame
47	 */
48	export function IsGoingToFreePure(
49	    round: number,
50	    roundQueueLen: number,
51	    isFreeGame: boolean
52	): boolean
53	{
54	    return round === 0 && roundQueueLen > 1 && !isFreeGame;
55	}
56	
57	/**
58	 * @ch IsGoingToRespinGame 投影
59	 *
60	 * 語意：當前 round 還有未播的 plate（sub 後面還有），即該局觸發了 Respin 且尚未播完。
61	 * plateCount ≤ 0 或缺值（呼叫端傳 0）→ 恆 false；單 plate（plateCount=1）→ false。
62	 *
63	 * @param sub        當前局內 plate 索引（CurSubPlateIndex）
64	 * @param plateCount 當前局 PlateQueue.length（缺值傳 0）
65	 */
66	export function IsGoingToRespinPure( sub: number, plateCount: number ): boolean
67	{
68	    return sub < plateCount - 1;
69	}
70	
71	/** @ch ResolveLockedEntries 回傳的單筆鎖定位置 */
72	export interface LockedEntry
73	{
74	    serverPos: number;
75	    col: number;
76	    row: number;
77	    symbol: number;
78	    number: number;
79	}
80	
81	/** @ch 盤面符號最小結構（對應 CColumn[]，僅取本模組需要的欄位） */
82	type PlateSymbolLike = ReadonlyArray<{
83	    Col?: ReadonlyArray<{ Symbol?: number; Number?: number } | null | undefined> | null;
84	} | null | undefined>;
85	
86	/**
87	 * @ch 將 server 給定的鎖定位置（serverPos[]）解碼為可顯示的 entry
88	 *
89	 * 注意：位置「由 server 給定」（PlateInfo.RespinLockedPos），本函式不掃描盤面找 Cash/Mystery，
90	 * 只負責「解碼 serverPos → col/row」並「從 plateSymbol 取出該格的 symbol/number」供演出用。
91	 *
92	 * fail-loud 邊界：解碼失敗 / col 缺 / cell 缺 → 跳過該筆並記入 warnings（呼叫端 console.warn），
93	 *                 不 throw（不炸狀態機）也不靜默。Number 缺值回 -1。
94	 *
95	 * @param plateSymbol     當前 plate 的 PlateSymbol（CColumn[]）
96	 * @param serverPositions PlateInfo.RespinLockedPos（serverPos 陣列）
97	 * @param decodePos       注入的解碼器（呼叫端餵 Common.DecodeServerPosByRowConfig）
98	 */
99	export function ResolveLockedEntries(
100	    plateSymbol: PlateSymbolLike | null | undefined,
101	    serverPositions: ReadonlyArray<number> | null | undefined,
102	    decodePos: ( serverPos: number ) => { col: number; row: number } | null
103	): { entries: LockedEntry[]; warnings: string[] }
104	{
105	    const entries: LockedEntry[] = [];
106	    const warnings: string[] = [];
107	
108	    if ( !serverPositions || serverPositions.length === 0 )
109	    {
110	        return { entries, warnings };
111	    }
112	
113	    for ( const serverPos of serverPositions )
114	    {
115	        const decoded = decodePos( serverPos );
116	        if ( !decoded )
117	        {
118	            warnings.push( `無法解碼 RespinLockedPos serverPos=${serverPos}` );
119	            continue;
120	        }
121	
122	        const { col, row } = decoded;
123	        const colData = plateSymbol?.[ col ]?.Col;
124	        if ( !colData )
125	        {
126	            warnings.push( `plateSymbol 缺 col=${col}（serverPos=${serverPos}）` );
127	            continue;
128	        }
129	
130	        const cell = colData[ row ];
131	        if ( !cell )
132	        {
133	            warnings.push( `plateSymbol 缺格子 (col=${col},row=${row})（serverPos=${serverPos}）` );
134	            continue;
135	        }
136	
137	        entries.push( {
138	            serverPos,
139	            col,
140	            row,
141	            symbol: cell.Symbol ?? -1,
142	            number: cell.Number ?? -1,
143	        } );
144	    }
145	
146	    return { entries, warnings };
147	}
