/**
 * @ch Respin 雙層索引純邏輯層（零 cc 依賴，可在 Node 跑）
 *
 * 為什麼獨立成檔：觸及 stateManager/GameView 的邏輯無既有自動化測試手段，
 * 把可測的判斷（游標推進 / 旗標投影 / 鎖定位置解碼）收進零依賴模組，
 * 是專案內唯一能放自動化測試的位置（對應 BC-1/2/3/9）。
 *
 * 設計原則：常數與解碼器一律由呼叫端「參數注入」，本模組不 import 任何
 * Cocos / Game_Define / Common，保持純函式可測。
 */

/**
 * @ch 雙層游標推進
 *
 * 規則：當前 round 內還有未播 plate（sub < plateCount-1）→ 只推 sub、round 不動；
 *       否則（當前 round 的 plate 已播完）→ round+1、sub 歸 0。
 *
 * 邊界：呼叫端在 round 無效（如 -1，剛 Reset）時傳 plateCount=0，
 *       則 0 < 0-1 不成立 → 走換局分支 round+1=0、sub=0（從 idle 進第一局）。
 *
 * @param round      當前局索引（CurPlateIndex）
 * @param sub        當前局內 plate 索引（CurSubPlateIndex）
 * @param plateCount 當前局（round 對應）的 PlateQueue.length；取不到傳 0
 */
export function AdvancePlateCursorPure(
    round: number,
    sub: number,
    plateCount: number
): { round: number; sub: number }
{
    if ( sub < plateCount - 1 )
    {
        return { round, sub: sub + 1 };
    }
    return { round: round + 1, sub: 0 };
}

/**
 * @ch IsGoingToFree 投影
 *
 * 語意：目前在 MainGame 局（round===0）且整包有多個 RoundInfo（觸發 FG）且尚未進 FG。
 * FG 進行中（isFreeGame=true）或非首局（round≠0）或單局（len≤1）皆為 false。
 *
 * @param round         當前局索引（CurPlateIndex）
 * @param roundQueueLen SpinAck.RoundQueue.length（缺值傳 0）
 * @param isFreeGame    GameView.IsFreeGame
 */
export function IsGoingToFreePure(
    round: number,
    roundQueueLen: number,
    isFreeGame: boolean
): boolean
{
    return round === 0 && roundQueueLen > 1 && !isFreeGame;
}

/**
 * @ch IsGoingToRespinGame 投影
 *
 * 語意：當前 round 還有未播的 plate（sub 後面還有），即該局觸發了 Respin 且尚未播完。
 * plateCount ≤ 0 或缺值（呼叫端傳 0）→ 恆 false；單 plate（plateCount=1）→ false。
 *
 * @param sub        當前局內 plate 索引（CurSubPlateIndex）
 * @param plateCount 當前局 PlateQueue.length（缺值傳 0）
 */
export function IsGoingToRespinPure( sub: number, plateCount: number ): boolean
{
    return sub < plateCount - 1;
}

/** @ch ResolveLockedEntries 回傳的單筆鎖定位置 */
export interface LockedEntry
{
    serverPos: number;
    col: number;
    row: number;
    symbol: number;
    number: number;
}

/** @ch 盤面符號最小結構（對應 CColumn[]，僅取本模組需要的欄位） */
type PlateSymbolLike = ReadonlyArray<{
    Col?: ReadonlyArray<{ Symbol?: number; Number?: number } | null | undefined> | null;
} | null | undefined>;

/**
 * @ch 將 server 給定的鎖定位置（serverPos[]）解碼為可顯示的 entry
 *
 * 注意：位置「由 server 給定」（PlateInfo.RespinLockedPos），本函式不掃描盤面找 Cash/Mystery，
 * 只負責「解碼 serverPos → col/row」並「從 plateSymbol 取出該格的 symbol/number」供演出用。
 *
 * fail-loud 邊界：解碼失敗 / col 缺 / cell 缺 → 跳過該筆並記入 warnings（呼叫端 console.warn），
 *                 不 throw（不炸狀態機）也不靜默。Number 缺值回 -1。
 *
 * @param plateSymbol     當前 plate 的 PlateSymbol（CColumn[]）
 * @param serverPositions PlateInfo.RespinLockedPos（serverPos 陣列）
 * @param decodePos       注入的解碼器（呼叫端餵 Common.DecodeServerPosByRowConfig）
 */
export function ResolveLockedEntries(
    plateSymbol: PlateSymbolLike | null | undefined,
    serverPositions: ReadonlyArray<number> | null | undefined,
    decodePos: ( serverPos: number ) => { col: number; row: number } | null
): { entries: LockedEntry[]; warnings: string[] }
{
    const entries: LockedEntry[] = [];
    const warnings: string[] = [];

    if ( !serverPositions || serverPositions.length === 0 )
    {
        return { entries, warnings };
    }

    for ( const serverPos of serverPositions )
    {
        const decoded = decodePos( serverPos );
        if ( !decoded )
        {
            warnings.push( `無法解碼 RespinLockedPos serverPos=${serverPos}` );
            continue;
        }

        const { col, row } = decoded;
        const colData = plateSymbol?.[ col ]?.Col;
        if ( !colData )
        {
            warnings.push( `plateSymbol 缺 col=${col}（serverPos=${serverPos}）` );
            continue;
        }

        const cell = colData[ row ];
        if ( !cell )
        {
            warnings.push( `plateSymbol 缺格子 (col=${col},row=${row})（serverPos=${serverPos}）` );
            continue;
        }

        entries.push( {
            serverPos,
            col,
            row,
            symbol: cell.Symbol ?? -1,
            number: cell.Number ?? -1,
        } );
    }

    return { entries, warnings };
}

