1	import { _decorator, error, log } from "cc";
2	import GameView from "../GameView";
3	import { BaseState, commonGameManager, eventManager, msgBoxManager, newBottombarManager, newExtraManager, stateManager } from "db://astarte-framework/Managers";
4	import { CommonState, Define } from "db://astarte-framework/utilis";
5	import { FeverGameType } from "../Game_Define";
6	import { FREE_GAME_ROUND_UI_EVENT } from "../FreeGame/FreeGameRoundUI";
7	import protocol from "@igs-arcade-division-rd2/uk_872_eyestrike2_proto/ar2es2Proto.js";
8	import { MULTIPLIER_EVENT } from "../Multiplier/MultiplierManager";
9	import { MAGIC_POT_EVENT } from "../MagicPot/MagicPotController";
10	import { FakeReelBetMode } from "../FakeReelManager";
11	const { ccclass } = _decorator;
12	
13	@ccclass( "UnshowPrepareState" )
14	export class UnshowPrepareState extends BaseState
15	{
16	    private m_gameView: GameView = null;
17	
18	    /** @ch 起始盤面索引 */
19	    private m_startRound: number = 0;
20	
21	    /** @ch 起始盤面資訊 */
22	    private m_startRoundInfo: protocol.ar2es2Proto.IRoundInfo = null;
23	
24	    /** @ch 上一輪累積贏分 */
25	    private m_previousAccumulatedWinValue: number = 0;
26	
27	    /** @ch 未顯示轉軸確認隊列 */
28	    private m_unshowSpinAckQue: protocol.ar2es2Proto.IRoundInfo[] = [];
29	
30	    constructor( gameView: GameView )
31	    {
32	        super();
33	        this.m_gameView = gameView;
34	    }
35	
36	    public async OnEnter()
37	    {
38	        if (!commonGameManager.HasUnshow) {
39	            log("[UnshowPrepareState] No unshow data, skip this state");
40	            return;
41	        }
42	
43	        log("OnEnter State: UnshowPrepare");
44	        newExtraManager.HasUnshow = false;
45	
46	        newBottombarManager.SetBarNodeVisiable(true);
47	        if (this.m_gameView.GameIntro) {
48	            this.m_gameView.GameIntro.node.active = false;
49	        }
50	
51	        this.m_unshowSpinAckQue = this.m_gameView.UnshowSpinAck?.RoundQueue ?? [];
52	        this.m_startRound = Math.trunc(commonGameManager.UnshowStartRound ?? 0);
53	        if (this.m_unshowSpinAckQue.length > 0) {
54	            const lastIndex = this.m_unshowSpinAckQue.length - 1;
55	            if (this.m_startRound < 0 || this.m_startRound > lastIndex) {
56	                error(`[UnshowPrepareState] startRound (${this.m_startRound}) out of range [0, ${lastIndex}]`);
57	                this.m_startRound = Math.min(Math.max(0, this.m_startRound), lastIndex);
58	            }
59	            this.m_gameView.SetUnshowPlateCursor( this.m_startRound );
60	            this.m_startRoundInfo = this.m_unshowSpinAckQue[this.m_startRound];
61	        }
62	        else {
63	            error("[UnshowPrepareState] RoundQueue is empty");
64	            this.m_startRound = 0;
65	            this.m_gameView.SetUnshowPlateCursor( 0 );
66	            this.m_startRoundInfo = null;
67	        }
68	
69	        this.m_previousAccumulatedWinValue = 0;
70	
71	        // 檢查是否為FreeGame 或 RespinGame
72	        if (
73	            this.m_unshowSpinAckQue.length > 1
74	            && this.m_startRound >= 1
75	            && this.m_startRound < this.m_unshowSpinAckQue.length
76	        ) {
77	            let plateSymbol = this.m_startRoundInfo?.PlateQueue?.[0]?.PlateSymbol ?? [];
78	            if (this.m_startRoundInfo.CurrFeverGameType === FeverGameType.FreeGame) {
79	                // 地Bar設定
80	                newBottombarManager.SetEnterFree();
81	
82	                // FG 旗標設定
83	                this.m_gameView.IsFreeGame = true;
84	                this.m_gameView.IsFirstRound = false;
85	
86	                plateSymbol = this.m_startRoundInfo?.PlateQueue?.[0]?.PlateSymbol ?? [];
87	            }
88	            // 原 else（CurrFeverGameType===RespinGame）為不可達死碼已刪：
89	            //   startRound≥1 ⟹ 必在 FreeGame（MG 僅 round 0），CurrFeverGameType 不會是 respin。
90	            //   Respin 中段斷線時 server UnshowStartRound 指回該 RoundInfo，從 plate 0（sub=0）重播整局，
91	            //   IsRespinGame 由流程重入 ENTER_RESPIN 自然重建（BC-8 待 Respin 上線實測）。
92	
93	            // 計算上一輪累積贏分
94	            for (let i = 0; i < this.m_startRound; i++) {
95	                this.m_previousAccumulatedWinValue += this.m_unshowSpinAckQue[i].RoundWin;
96	            }
97	
98	            // 設定起始盤面即上一手盤面
99	            this.m_gameView.SlotReels.SetPlateSymbolForUnshow(plateSymbol);
100	
101	            // 原 if(IsRespinGame) HandleRespinGame()：unshow 不再以 Respin 身分恢復，改從 plate 0（sub=0）
102	            // 重播整局、由流程重入 ENTER_RESPIN 自然重建鎖定（BC-8 待 Respin 上線實測）。
103	        }
104	
105	        // 恢復背景音樂
106	        this.RestoreBgm();
107	
108	        // 恢復UI
109	        await this.RestoreUI();
110	
111	        msgBoxManager.ShowMessageBox(
112	            Define.StringKey.MSGBOX_UNSHOW_BACK,
113	            Define.StringKey.MSGBOX_TITLE_SYSTEM_INFO,
114	            () => {
115	                stateManager.NextState(CommonState.SPIN);
116	            }
117	        );
118	    }
119	
120	    public OnProcess()
121	    {
122	    }
123	
124	    public OnLeave()
125	    {
126	        this.m_startRoundInfo = null;
127	        this.m_previousAccumulatedWinValue = 0;
128	    }
129	
130	    /**
131	     * @ch 恢復FreeGame UI
132	     */
133	    private RestoreFreeGameUI()
134	    {
135	        log( "RestoreFreeGameUI" );
136	
137	        // 初始化免費遊戲回合數字
138	        const nowRound = this.m_startRoundInfo?.FreeNowRound ?? 0;
139	        const totalRound = this.GetFreeGameTotalRound();
140	        eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.INIT, nowRound, totalRound );
141	        eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.SHOW );
142	
143	        // 恢復贏分
144	        this.RestoreWinValue();
145	    }
146	
147	    /**
148	     * @ch 恢復RespinGame UI
149	     */
150	    private RestoreRespinGameUI()
151	    {
152	        log( "RestoreRespinGameUI" );
153	
154	        // 恢復贏分
155	        this.RestoreWinValue();
156	    }
157	
158	    /**
159	     * @ch 恢復MainGame UI
160	     */
161	    private RestoreMainGameUI()
162	    {
163	        log( "RestoreMainGameUI" );
164	
165	        // 若有需要恢復其他UI，請在此處實作
166	    }
167	
168	    /**
169	     * @ch 恢復Extra Bet UI
170	     */
171	    private async RestoreExtraBetUI()
172	    {
173	        log( "RestoreExtraBetUI" );
174	
175	        // 先把假轉輪 betMode 快取設好，避免 ForceSetExtraBet 內 ChangeMultiBet 連帶讀到舊值
176	        this.m_gameView.ForceSetFakeReelBetMode(FakeReelBetMode.ExtraBet);
177	        await this.m_gameView.RestoreExtraBetState();
178	    }
179	
180	    /**
181	     * @ch 恢復所有UI
182	     */
183	    private async RestoreUI()
184	    {
185	        this.m_gameView.CheckBackground();
186	        if (this.m_gameView.IsFreeGame) {
187	            this.RestoreFreeGameUI();
188	        }
189	        else if (this.m_gameView.IsRespinGame) {
190	            this.RestoreRespinGameUI();
191	        }
192	        else {
193	            this.RestoreMainGameUI();
194	        }
195	
196	        if (this.m_startRoundInfo) {
197	            // // 設定倍率
198	            // eventManager.Dispatch(MULTIPLIER_EVENT.SET_INDEX, this.m_startRoundInfo.PreMultiplierIndex, true);
199	
200	            // 設定魔法罐等級
201	            eventManager.Dispatch(MAGIC_POT_EVENT.SET_LEVEL, this.m_startRoundInfo.PreScAccuStage);
202	        }
203	
204	        if (this.m_gameView.UnshowSpinAck != null && commonGameManager.UnshowBaseBet < commonGameManager.UnshowRealBet) {
205	            await this.RestoreExtraBetUI();
206	        }
207	    }
208	
209	    /**
210	     * @ch 恢復贏分
211	     */
212	    private RestoreWinValue()
213	    {
214	        log( "RestoreWinValue" );
215	
216	        const totalWin = this.m_gameView.UnshowSpinAck?.TotalWin ?? 0;
217	        newBottombarManager.SetWinValueWithCheck( { maxWin: totalWin, value: this.m_previousAccumulatedWinValue } );
218	    }
219	
220	    /**
221	     * @ch 取得免費遊戲總回合數
222	     * @return 免費遊戲總回合數
223	     */
224	    private GetFreeGameTotalRound(): number
225	    {
226	        if (this.m_unshowSpinAckQue.length === 0) {
227	            error("[UnshowPrepareState] UnshowSpinAckQue is empty");
228	            return 0;
229	        }
230	
231	        // 如果起始盤面索引大於0，則返回上一輪的免費遊戲總回合數
232	        if (this.m_startRound >= 1 && this.m_startRound < this.m_unshowSpinAckQue.length) {
