import { _decorator } from "cc";
import { log } from "cc";
import GameView from "../GameView";
import { BaseState, stateManager } from "db://astarte-framework/Managers";
import Game_Define from "../Game_Define";

const { ccclass } = _decorator;

@ccclass( "CheckState" )
export class CheckState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        log( "OnEnter state : CHECK_STATE" );

        // 優先序重排（v2）：plate 內循環（Respin）優先於換局，繞過 ROUND_END。
        // 旗標改唯讀 getter，不再賦值清除（CurPlateIndex/CurSubPlateIndex 推進後 getter 自動翻轉）。

        // ① 當前局還有未播 plate → 首手與連鎖續轉同路徑（ENTER_RESPIN 之後 → SPIN 播下一手）
        if ( this.m_gameView.IsGoingToRespinGame )
        {
            stateManager.NextState( Game_Define.GameState.ENTER_RESPIN );
        }
        // ② 在 Respin 中且 plate 已用盡（①不成立 ⇒ 必已播完）→ 離開 Respin
        else if ( this.m_gameView.IsRespinGame )
        {
            stateManager.NextState( Game_Define.GameState.LEAVE_RESPIN );
        }
        // ③ MainGame 局結束要進 FreeGame
        else if ( this.m_gameView.IsGoingToFree )
        {
            stateManager.NextState( Game_Define.GameState.ENTER_FREE );
        }
        // ④ FreeGame 最後一局 → 離開 FG
        else if (
            this.m_gameView.IsFreeGame
            && this.m_gameView.CurPlateIndex + 1 === this.m_gameView.SpinAck.RoundQueue.length
        )
        {
            stateManager.NextState( Game_Define.GameState.LEAVE_FREE );
        }
        // ⑤ 一般局結束（RoundInfo 級 ROUND_END，ReqRoundEnd 一次）
        else
        {
            stateManager.NextState( Game_Define.GameState.ROUND_END );
        }
    }

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }
}

