import { _decorator } from "cc";
import GameView from "../GameView";
import { log } from "cc";
import { BaseState, stateManager } from "db://astarte-framework/Managers";
import Game_Define from "../Game_Define";

const { ccclass } = _decorator;

@ccclass( "LeaveRespinState" )
export class LeaveRespinState extends BaseState
{
    private m_gameView: GameView = null;

    /**
     * @ch 是否需要展示特色
     */
    public IsNeedFeatureDemo: boolean = false; 

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        log( "OnEnter State: LEAVE_RESPIN" );

        // Respin 結束
        this.m_gameView.IsRespinGame = false;

        // 解除Respin鎖定列的旋轉鎖定
        Game_Define.RespinLockColumns.forEach( column => {
            this.m_gameView.SlotReels.SetColumnLock( column, false );
        } );

        // fail-loud 斷言：累積鎖定集合 vs 該局所有 plate RespinLockedPos 聯集（P-3/P-5 碼上不可證，僅 log）
        this.AssertLockedConsistency();

        // 清空累積鎖定集合
        this.m_gameView.ClearRespinLocks();

        // 去向（補 ENTER_FREE 分支，F-1 修復）：LEAVE_RESPIN 後控制權不回 CheckState，必須內聯派發
        // ① MainGame 局 Respin 完才進 FG（旗艦場景）
        if ( this.m_gameView.IsGoingToFree )
        {
            stateManager.NextState( Game_Define.GameState.ENTER_FREE );
        }
        // ② FreeGame 最後一局 → 離開 FG（沿用原判斷）
        else if ( this.m_gameView.IsFreeGame && this.m_gameView.CurPlateIndex + 1 === this.m_gameView.SpinAck.RoundQueue.length )
        {
            stateManager.NextState( Game_Define.GameState.LEAVE_FREE );
        }
        // ③ 一般局結束（含 FG 非末局 → ForEndToNext 回 SPIN 播下一局）
        else
        {
            stateManager.NextState( Game_Define.GameState.ROUND_END );
        }
    }

    /**
     * @ch fail-loud 一致性斷言：累積鎖定集合 keys 應等於該局所有 plate 的 RespinLockedPos 聯集。
     * 增量語意下最後一手 RespinLockedPos 預期為空（不再切下一手），故聯集 = 累積集合。
     * 不一致僅 console.error（不改控制流——P-3/P-5 為協議前提，偏離要看得見而非炸狀態機）。
     */
    private AssertLockedConsistency(): void
    {
        const expected = new Set<number>();
        this.m_gameView.RoundInfo?.PlateQueue?.forEach( plate => {
            plate?.RespinLockedPos?.forEach( pos => expected.add( pos ) );
        } );

        const actual = this.m_gameView.RespinLockedSet;
        let mismatch = actual.size !== expected.size;
        if ( !mismatch )
        {
            for ( const key of actual.keys() )
            {
                if ( !expected.has( key ) ) { mismatch = true; break; }
            }
        }
        if ( mismatch )
        {
            console.error( `[LeaveRespinState] 鎖定集合與 server RespinLockedPos 聯集不一致：`
                + `累積=[${Array.from( actual.keys() )}] vs server聯集=[${Array.from( expected )}]` );
        }
    }

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }
}

