120	        if (this.m_gameView.SpinAck && this.m_gameView.SpinAck.RoundQueue)
121	        {
122	            for (let i = 0; i < this.m_gameView.CurPlateIndex; i++)
123	            {
124	                const roundInfo = this.m_gameView.SpinAck.RoundQueue[i];
125	                if (roundInfo && roundInfo.RoundWin)
126	                {
