137	     * @param thisRoundWin 當前輪贏分
138	     * @param rate 倍率
139	     * @param winType 獲勝類型
140	     */
141	    private async HandleNormalGameAward(thisRoundWin: number, rate: number, winType: WinType): Promise<void>
142	    {
