162	            newBottombarManager.SetSpinState( SlotBottomBarState.GET_AWARD_NO_AUTO );
163	            await this.m_gameView.ShowBigWin(thisRoundWin, rate, winType);
164	            // 使用跑分動畫方式設定贏分（等待 BigWin 動畫完成後才設定）
165	            newBottombarManager.SetWinValueWithRunning(thisRoundWin, 0.1);
166	        }
167	    }
168	
169	    /**
170	     * @ch 處理 FreeGame 狀態下的獲勝值計算
171	     * @param thisRoundWin 當前輪贏分
172	     * @param rate 倍率
173	     * @param winType 獲勝類型
174	     */
175	    private async HandleFreeGameAward(thisRoundWin: number, rate: number, winType: WinType): Promise<void>
176	    {
177	        // 如果沒有中獎，不顯示抱獎演出
178	        if (thisRoundWin <= 0 || winType === WinType.NoWin)
179	        {
180	            return;
181	        }
182	
183	        // FreeGame 狀態下需要累積所有輪的贏分
184	        // 計算累積的總贏分（包括之前所有 FreeGame 輪的贏分）
185	        const accumulatedWinValue = this.CalculateFreeGameWinValue();
186	        const totalWin = this.m_gameView.SpinAck?.TotalWin ?? 0;
187	
188	        if (winType === WinType.NormalWin)
189	        {
190	            await Define.Wait( this.m_gameView, 0.3 );
191	            await this.m_gameView.EffectPlate.ShowSymbolEffect();
192	            // FreeGame 狀態下：使用累積的總贏分（會自動從之前的值累加顯示）
193	            newBottombarManager.SetWinValueWithRunning(accumulatedWinValue, 0.1);
194	            await this.m_gameView.SmallWin.SetWinLabelRunning( thisRoundWin, 0.1 );
195	            await Define.Wait( this.m_gameView, 0.15 );
196	        }
197	        else
198	        {
199	            this.m_gameView.BigWin.IsEnd = false;
200	            await Define.Wait( this.m_gameView, 0.3 );
201	            await this.m_gameView.EffectPlate.ShowSymbolEffect( false );
202	            newBottombarManager.SetSpinState( SlotBottomBarState.GET_AWARD_NO_AUTO );
203	            await this.m_gameView.ShowBigWin(thisRoundWin, rate, winType);
204	            newBottombarManager.SetWinValueWithCheck({ maxWin: totalWin, value: accumulatedWinValue });
205	        }
