232	    /**
233	     * @ch 計算 FreeGame 的獲勝值
234	     * @returns FreeGame 狀態下的獲勝值
235	     */
236	    private CalculateFreeGameWinValue(): number
237	    {
238	        return this.CalculateAccumulatedWin();
239	    }
240	
241	    /**
242	     * @ch 計算累計贏分（雙層）：已完成局用整局 RoundWin，當前局用已播 plate 的 Win 逐手累加（含當手）。
243	     * 取代原「Σ RoundWin (i≤CurPlateIndex)」——雙層下整局 RoundWin 含未播 Respin 手贏分，會提前上 bar。
244	     * V-2：依賴 RoundWin=Σ PlateInfo.Win（P-5），待對拍；FG 非 Respin 局（單 plate）與原邏輯等價。
245	     */
246	    private CalculateAccumulatedWin(): number
247	    {
248	        const queue = this.m_gameView.SpinAck?.RoundQueue;
249	        if (!queue) return 0;
250	
251	        let total = 0;
252	        // 已完成局：整局 RoundWin
253	        for (let i = 0; i < this.m_gameView.CurPlateIndex; i++)
254	        {
255	            total += queue[i]?.RoundWin ?? 0;
256	        }
257	        // 當前局：已播 plate 的 Win 逐手累加（含當手 sub）
258	        const curPlates = queue[ this.m_gameView.CurPlateIndex ]?.PlateQueue;
259	        for (let j = 0; j <= this.m_gameView.CurSubPlateIndex; j++)
260	        {
261	            total += curPlates?.[j]?.Win ?? 0;
262	        }
263	        return total;
264	    }
265	
266	    /**
267	     * @ch 計算 RespinGame 的獲勝值
268	     * @returns RespinGame 狀態下的獲勝值
269	     */
270	    private CalculateRespinWinValue(): number
271	    {
272	        return this.CalculateAccumulatedWin();
273	    }
274	
275	    /**@ch 清理板面上所有殘留的 layer TWO spine，Collect / CollectAndRetrigger 除外 */
276	    private CleanNonCollectSpines(): void
277	    {
278	        const plate = this.m_gameView.SlotReels.PlateInfo;
279	        for ( let col = 0; col < plate.length; col++ )
280	        {
281	            const column = plate[ col ];
282	            if ( !column?.Col ) continue;
283	            for ( let row = 0; row < column.Col.length; row++ )
284	            {
285	                const sym = column.Col[ row ]?.Symbol;
286	                if ( sym === Game_Define.Symbol.Collect || sym === Game_Define.Symbol.CollectAndRetrigger )
287	                {
288	                    continue;
289	                }
290	                this.m_gameView.EffectPlate.CleanSymbolSpineAt( col, row, Game_Define.LAYERS.TWO );
291	            }
292	        }
293	    }
294	
295	    /**@ch 秀中獎表演 */
296	    private async ShowSymbolEffect()
297	    {
298	        await this.m_gameView.EffectPlate.ShowSymbolEffect();
299	    }
300	
301	}

