import { Enum, Vec3, color, v3 } from "cc";
import { newBottombarManager } from "db://astarte-framework/Managers";

/**@ch 贏分類型 */
export enum WinType {
    NoWin,

    NormalWin,

    /** 5 <= 倍率 < 10 */
    BigWin,

    /** 10 <= 倍率 < 25 */
    MegaWin,

    /** 25 <= 倍率 < 50 */
    SuperWin,

    /** 50 <= 倍率 */
    UltimateWin,
}

/**@ch 遊戲狀態 */
enum GAMEVIEW_STATE
{
    WAIT_READY,
    PLATE_SHOW,
    FEATURE_SHOW,
    UNSHOW_PREPARE,
    AWARD,
    ROUND_SHOW_END,
    ROUND_END,

    EFFECT_START,
    // CHECK_JP,
    SCATTER_SHOW,
    ENTER_FREE,
    FULL_REWARD,
    LEAVE_FREE,
    ADD_FREE,

    ENTER_RESPIN,
    LEAVE_RESPIN,
}

/**
 * @ch 符號類型 需與SlotReels的symbol擺放順序相同
 */
export enum Symbol
{
    /**WILD*/
    WILD,

    /**M1*/
    M1,

    /**M2*/
    M2,

    /**M3*/
    M3,

    /**M4*/
    M4,

    /**M5*/
    M5,

    /**A*/
    A,

    /**K*/
    K,

    /**Q*/
    Q,

    /**J*/
    J,

    /**10*/
    Ten,

    /**9*/
    Nine,

    /**SCATTER*/
    Scatter = 12,

    /**Collect*/
    Collect = 13,

    /**Cash*/
    Cash = 14,

    /**乘倍*/
    Wheel = 15,

    /**Server用的Symbol*/
    ServerSymbol = 16,

    /**Retrigger*/
    Retrigger = 17,

    /**CollectAndRetrigger*/
    CollectAndRetrigger = 18,

    /**空格*/
    Blank = 19,

    /**神秘 (可轉換為其他Symbol：Cash、Jackpot)*/
    Mystery = 20,
}

/**@ch Jackpot類型 */
export enum Jackpot
{
    Mini,
    Minor,
    Major,
    Mega,
    Grand,
}

/**@ch 特效Prefabs類型 */
export enum AddEffectPrefabs
{
    /**@ch 中獎框*/
    FX_FRAME,

    /**@ch 金幣特效*/
    SCATTER_FX
}

/**@ch 符號資訊 */
export class SymbolInfo
{
    /**@ch 符號ID*/
    Symbol: number;

    /**@ch 符號值*/
    Value: number;

    /**@ch JP類型*/
    JpType: number;
}

/**@ch 顯示符號資訊 */
export class ShowSymbolInfo
{
    /**@ch 符號*/
    Symbol: number;

    /**@ch 位置*/
    Position: { col: number; row: number };
}

/**@ch 特殊功能位置佇列*/
export enum FeaturePosQueueType
{
    /**@ch Scatter 出現位置*/
    Scatter = 0,

    /**@ch Collect 出現位置*/
    Collect = 1,

    /**@ch Retrigger 觸發位置*/
    Retrigger = 2,

    /**@ch 倍數符號位置*/
    Multiplier = 3,

    /**@ch 現金符號位置*/
    Cash = 4,

    /**@ch 神秘現金符號(Coin or Jackpot)位置*/
    MysteryCash = 5,

    /**@ch 神秘現金JP位置*/
    MysteryCashJackpot = 6,

    /**@ch 左邊Collect位置*/
    CollectLeft = 7,

    /**@ch 右邊Collect位置*/
    CollectRight = 8,
}

/**@ch 遊戲類型*/
export enum FeverGameType
{
    /**@ch 主遊戲*/
    MainGame = 0,

    /**@ch 免費遊戲*/
    FreeGame = 1,

    /**@ch 旋轉遊戲*/
    RespinGame = 2,

    /**@ch 免費遊戲中的Respin遊戲*/
    RespinInFreeGame = 3,
}

/**@ch 神秘事件類型*/
export enum MysteryEventKind
{
    None = 0,

    /**@ch FG預中*/
    FreeGame,

    /**@ch 大獎預中*/
    BigWin,
}

/**@ch 聽牌類型*/
export enum NearMissKind
{
    None = 0,

    /**@ch FG聽牌*/
    FreeGame,

    /**@ch 大獎聽牌*/
    BigWin,
}

/**@ch 轉輪符號顯示模式*/
export enum ReelSymbolMode
{
    /**@ch 正常：顯示原始符號*/
    Normal,

    /**@ch 只顯示Blank符號*/
    OnlyBlank,

    /**@ch 依權重產生Cash或Blank（Cash Value來自GENERATE_COIN_CREDIT）*/
    CashAndBlank,

    /**@ch 依權重產生Multiplier或Blank */
    MultiplierAndBlank,
}

export default class Game_Define
{
    static Ver: string = "Ver";
    static BgAudioId: number = -1;
    static SPICY_LEVEL = 2;
    static Symbol = Enum( Symbol );
    static GameState = Enum( GAMEVIEW_STATE );

    /**@ch For盤面壓黑 */
    static Color = {
        Light: color( 255, 255, 255 ),
        Dark: color( 101.25, 94.5, 73.5 ),
    };

    /**@ch 取得當前BET，會受extraBet影響 */
    static GetNowBetValue()
    {
        return newBottombarManager.GetNowBetValue();
    }

    static EVENT = {
        DEVICE_ROTATION: "GAME_VIEW_DEVICE_ROTATION",
    };


    /************************** 多語系 **************************/

    /**@ch 列數*/
    static COL = 6;

    /**
     * @ch 盤面佈局模式
     * - true = 1 代 server 過渡期 [5,4,4,4,4,5]（26 格）
     * - false = 2 代 server [4,4,4,4,4,4]（24 格）
     * TODO(2 代 server 上線): 改為 false 並執行 BC-6 toggle 驗證
     */
    static readonly LEGACY_PLATE_LAYOUT: boolean = false;

    static readonly ROW: number = Game_Define.LEGACY_PLATE_LAYOUT ? 5 : 4; // 最大行數
    static readonly ROW_CONFIG: readonly number[] = Game_Define.LEGACY_PLATE_LAYOUT
        ? [5, 4, 4, 4, 4, 5]
        : [4, 4, 4, 4, 4, 4]; // 每列的行數配置 [Col0, Col1, Col2, Col3, Col4, Col5]
    static readonly FULL_PLATE_NUM: number = Game_Define.LEGACY_PLATE_LAYOUT ? 26 : 24; // 總符號數
    static readonly MAX_ROW: number = Game_Define.LEGACY_PLATE_LAYOUT ? 5 : 4; // 最大行數
    static MIN_ROW = 4; // 最小行數（兩模式 min 都是 4）

    static MAX_SCATTER = 3;

    // 列索引常數
    static FIRST_COL = 0; // 第一列（左邊）
    static LAST_COL = 5; // 最後一列（右邊）

    // 中間列範圍
    static MIDDLE_COLS_START = 1; // 中間列開始索引
    static MIDDLE_COLS_END = 4; // 中間列結束索引
    static SeparateLineWidth = 0; // pixels
    static SymbolHeight = 82
    static SymbolWidth = 96;

    static IsFG: boolean = false;
    static CanScaleWinValue = true;

    static InitSize: Vec3 = v3( 0.1, 0.1 );
    static EndSize: Vec3 = v3( 1, 1 );

    /**@ch 表演輪(中)，實際轉輪 */
    static MIDDLE_PLATE_INDEX = 1;

    static NODE_PREFIX_NAME = [
        "low",
        "",
        "up"
    ];

    static THOUSAND = 1000;
    static MILLION = 1000000;

    /**@ch 飛行特效種類*/
    static FLY_TYPES = 4;

    /**@ch Effect表演分層數(4)，視各遊戲需求*/
    static EFFECT_LAYER_NUMS = 4;
    static LAYERS = {
        ONE: 0,
        TWO: 1,
        THREE: 2,
        FOUR: 3,
    };

    /**@ch 遊戲中須創造之表演大分類，(以此三幣瑞龍為例，symbol算一種、飛行特效算一種、盤面共用中獎特效算一種) */
    static EFFECT_TYPES = 5;
    static EFFECT_TYPE = {
        SYMBOL: 0,
        ADD_EFFECT: 1,
        FLY: 2,
        STATIC_SYMBOL: 3,
        SELECT_FRAME: 4,
    };

    static ADD_EFFECT_TYPE = {
        MG: 0,
        FG: 1
    };

    /**@ch 部分表演DELAY時長*/
    static ACTION_DELAY_TIME = {
        TIME_FOR_AWARD_LINE_EFFECT: 1.5,
    };

    static SpeedUp = 1;

    static ActualFlyTime = 0.5;
    static WaitTime = 0.75;
    static HitTime = 0.15;

    static SymbolWinName = "Win";
    static SymbolBingoName = "Bingo";
    static SymbolCollectName = "Collect";

    static PlateEftOdds = [ 1, 15, 30, 50, 100 ];

    /**@ch Respin鎖定列*/
    static RespinLockColumns = [0, 5];

    static GetWinType( odds: number)
    {
        if(odds <= 0)
            return WinType.NoWin;
        const [normalWinMinThreshold, youWinMinThreshold, bigWinMinThreshold, megaWinMinThreshold, superWinMinThreshold] = this.PlateEftOdds;

        // 從小到大依序判斷倍數範圍
        if( odds < normalWinMinThreshold )
            return WinType.NormalWin;
        else if( odds < youWinMinThreshold )
            return WinType.NormalWin;     // 1-14倍
        else if( odds < bigWinMinThreshold )
            return WinType.BigWin;        // 15-29倍
        else if( odds < megaWinMinThreshold )
            return WinType.MegaWin;        // 30-49倍
        else if( odds < superWinMinThreshold )  
            return WinType.SuperWin;       // 50-99倍
        else
            return WinType.UltimateWin;      // 100倍以上
    }

    static StringKey = {
        MC_FEATURES_LEFT: "MC_FEATURES_LEFT",
        MC_FEATURES_RIGHT: "MC_FEATURES_RIGHT",
        FREE_GAME_NAME_STRING: "FREE_GAME_NAME_STRING",
        EXTRA_BET_DESC: "EXTRA_BET_DESC",
        MG_SPECIAL_TXT: "MG_specialTXT_01s",
    };

    static ShowDisplayValue: ( value: number ) => number = null;

    /**@ch 特色遊玩押注 */
    static FeatureBetValue = 10;

    static OnExit()
    {
        this.BgAudioId = -1;
        this.ShowDisplayValue = null;
    }
}

