92	 * 全為 None（如 server 給 [-1] / [-1,-1]）或缺值（null/空陣列）→ 無轉輪、不進演出 State。
93	 *
94	 * @param types RoundInfo.WheelFeatures.map(w => w.Type)（缺值傳 null/undefined）
95	 */
96	export function HasActiveWheel(types: ReadonlyArray<number> | null | undefined): boolean {
97	    return !!types && types.some(t => t !== FeatureWheelSegmentType.None);
98	}
99	
100	/**
101	 * @ch 預設 12 格 fallback 組成（server 整層無資料時用）
102	 * 3 符號轉換 + 3 乘倍 + 3 升級 + 1 GRAND JP + 1 Free Game + 1 升級補滿
103	 */
104	export function GetDefaultSegments(): SegmentDescriptor[] {
105	    return [
106	        { type: FeatureWheelSegmentType.SymbolConvert },
107	        { type: FeatureWheelSegmentType.Multiplier },
108	        { type: FeatureWheelSegmentType.Upgrade },
109	        { type: FeatureWheelSegmentType.SymbolConvert },
110	        { type: FeatureWheelSegmentType.Multiplier },
111	        { type: FeatureWheelSegmentType.Upgrade },
112	        { type: FeatureWheelSegmentType.SymbolConvert },
113	        { type: FeatureWheelSegmentType.Multiplier },
114	        { type: FeatureWheelSegmentType.Upgrade },
115	        { type: FeatureWheelSegmentType.GrandJP },
116	        { type: FeatureWheelSegmentType.Upgrade },
117	        { type: FeatureWheelSegmentType.FreeGame },
118	    ];
119	}
120	
121	/** @ch WheelData 第一層索引語意（0:主遊戲 1:免費遊戲） */
122	export enum WheelDataLayer {
123	    MainGame = 0,
124	    FreeGame = 1,
125	}
126	
127	/**
128	 * @ch server 介面隔離 adapter（BC-1 / BC-2）
129	 * WheelData 結構：IIntAry[]，第一層 = WheelDataLayer（0:MG 1:FG），第二層 Data = 各格的功能類型 int。
130	 * client enum 目前與 server 同號 → 直接 passthrough（驗證已知值，未知/缺格 → None 不顯示）。
131	 * 若後端改號，改回此處加映射層即可（呼叫端與型別不變）。
132	 * 整層無資料（缺層 / Data 非陣列 / Data 為空）→ 回預設 12 格。
133	 * @param raw server 原始 WheelData（protocol.ar2es2Proto.IIntAry[]；用結構化簽章避免依賴 proto 型別，保住純邏輯層）
134	 * @param layer 取主遊戲或免費遊戲那一層
135	 * @returns 剛好 12 格的 SegmentDescriptor 陣列
136	 */
137	export function ParseServerWheelData(
138	    raw: ReadonlyArray<{ Data?: number[] | null }> | null | undefined,
139	    layer: WheelDataLayer,
140	): SegmentDescriptor[] {
141	    const fallback = GetDefaultSegments();
142	
143	    // 整層無資料 → 全 fallback（BC-2 / 用戶確認：沒有任何資料時用原本預設）
144	    const layerData = Array.isArray(raw) ? raw[layer]?.Data : null;
145	    if (!Array.isArray(layerData) || layerData.length === 0) {
146	        return fallback;
147	    }
148	
149	    // 有資料：固定 12 格逐格採用（已知值直接用；未知值 / 缺格 / 非數字 → None 不顯示）
150	    const result: SegmentDescriptor[] = [];
151	    for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
152	        const v = layerData[i];
153	        const type = (typeof v === 'number' && IsKnownSegmentType(v))
154	            ? (v as FeatureWheelSegmentType)
155	            : FeatureWheelSegmentType.None;
156	        result.push({ type });
157	    }
158	    return result;
159	}
160	
161	/**
162	 * @ch 計算單調的絕對目標角（BC-3）
163	 * 順時針（預設）→ z 角遞減；逆時針 → z 角遞增。兩方向落點 orientation 同為 baseAngle。
164	 * Cocos +z 為逆時針，故順時針取負向 delta，再疊固定額外圈數，全程不變號（避免視覺反向）。
165	 * 不沿用 MultiplierManager 的 angleDiff = target - start（會中途反向）。
166	 * @param landIndex 落點格索引 (0~11)
167	 * @param currentAngle 輪盤當前角度（度，取自節點 eulerAngles.z）
168	 * @param clockwise 是否順時針（預設 true）
169	 * @returns 絕對目標角（度）；clockwise=true 時 < currentAngle，false 時 > currentAngle
170	 */
171	export function ComputeTargetAngle(landIndex: number, currentAngle: number, clockwise: boolean = true): number {
172	    const baseAngle = landIndex * FEATURE_WHEEL_SEGMENT_ANGLE;
173	    const extra = FEATURE_WHEEL_EXTRA_CIRCLES * 360;
174	    if (clockwise) {
175	        // 順時針：z 角遞減。backwardDelta 取正向（0~360）使落點對齊 base，再多轉 extra 整圈
176	        const backwardDelta = NormalizeAngle(currentAngle - baseAngle);
177	        return currentAngle - backwardDelta - extra;
178	    }
179	    // 逆時針：z 角遞增。forwardDelta 取正向（0~360），等同 NormalizeAngle(baseAngle - currentAngle)
180	    const forwardDelta = NormalizeAngle(baseAngle - currentAngle);
181	    return currentAngle + forwardDelta + extra;
182	}
183	
184	/**
185	 * @ch 正規化角度到 0~360（每次轉動結束後呼叫，防 BC-8 連續轉動的累積漂移 · DR-9）
186	 * @param angle 任意角度（度）
187	 */
188	export function NormalizeAngle(angle: number): number {
189	    return ((angle % 360) + 360) % 360;
190	}

