1	import { _decorator, error, log } from "cc";
2	import { stateManager, BaseState, newBottombarManager, eventManager } from "db://astarte-framework/Managers";
3	import GameView from "../GameView";
4	import Game_Define, { ReelSymbolMode } from "../Game_Define";
5	import { Define } from "db://astarte-framework/utilis";
6	import { GOLD_BLITZ_ROULETTE_EVENT } from "../FreeGame/GoldBlitzRoulette";
7	import { WaitUntil } from "../Common/AsyncUtils";
8	import { FREE_GAME_ROUND_UI_EVENT } from "../FreeGame/FreeGameRoundUI";
9	import { MULTIPLIER_EVENT, MultiplierType } from "../Multiplier/MultiplierManager";
10	import { SHOW_ADD_MULTIPLIER_EVENT } from "../Multiplier/ShowAddMultiplier";
11	import { FLY_EVENT } from "../FlyManager";
12	import { BLACK_MASK_EVENT } from "../BlackMaskManager";
13	import { REEL_MANAGER_EVENT } from "../ReelManager";
14	import { JP_EVENT } from "../JP/JP_Define";
15	import { BACKGROUND_UI_EVENT } from "../BackgroundManager";
16	import { Common } from "../Common/Common";
17	import { MAGIC_POT_EVENT } from "../MagicPot/MagicPotController";
18	
19	const { ccclass } = _decorator;
20	
21	// 進入免費遊戲狀態前的初始等待時間
22	const ENTER_FREE_INITIAL_DELAY_SECONDS = 1.5;
23	
24	// 輪盤初始化後，開始後續流程前的等待時間
25	const GOLD_BLITZ_ROULETTE_INIT_DELAY_SECONDS = 0.5;
26	
27	// 輪盤進場前，隱藏其他 UI 的延遲時間
28	const GOLD_BLITZ_ROULETTE_HIDE_OTHER_UI_DELAY_SECONDS = 0.5;
29	
30	// 輪盤完成後，重新顯示其他 UI 的延遲時間
31	const GOLD_BLITZ_ROULETTE_SHOW_OTHER_UI_DELAY_SECONDS = 3;
32	
33	// 現金飛分演出次數
34	const FREE_GAME_ADD_CASH_ANIMATION_COUNT = 15;
35	
36	// 現金飛分演出的目標索引
37	const FREE_GAME_ADD_CASH_ANIMATION_TARGET_INDEXES = [0, 1, 2, 3, 4, 5];
38	
39	// 現金飛分演出的每次間隔時間
40	const FREE_GAME_ADD_CASH_ANIMATION_INTERVAL_SECONDS = 0.1;
41	
42	/**@ch EnterFreeState 狀態機階段*/
43	enum EnterFreeStatePhase {
44	    IDLE = 0,                      // 初始狀態
45	    SPINNING = 1,                  // 轉輪旋轉中，等待演出完成
46	    COMPLETED = 2                  // 轉輪停止，演出完成，準備跳轉
47	}
48	
49	@ccclass( "EnterFreeState" )
50	export class EnterFreeState extends BaseState
51	{
52	    private m_gameView: GameView = null;
53	
54	    /**@ch 是否播放輪盤完成*/
55	    private m_isPlayGoldBlitzRouletteFinish: boolean = false;
56	
57	    /**@ch 當前狀態階段*/
58	    private m_phase: EnterFreeStatePhase = EnterFreeStatePhase.IDLE;
59	
60	    /**@ch 倍率演出是否完成*/
61	    private m_isMultiplierAnimFinish: boolean = false;
62	
63	    /**@ch 現金演出是否完成*/
64	    private m_isCashAnimFinish: boolean = false;
65	
66	    constructor( gameView: GameView )
67	    {
68	        super();
69	        this.m_gameView = gameView;
70	    }
71	
72	    public async OnEnter()
73	    {
74	        log( "OnEnter State : ENTER_FREE" );
75	
76	        await Define.Wait(this.m_gameView, ENTER_FREE_INITIAL_DELAY_SECONDS);
77	
78	        // 暫停主遊戲背景音樂
79	        this.m_gameView.PauseMainGameBgm();
80	
81	        newBottombarManager.SetEnterFree();
82	        this.StopEffect();
83	        this.m_gameView.IsFreeGame = true;
84	
85	        newBottombarManager.SetBarNodeVisiable( false );
86	        this.m_gameView.BuyBonus?.SetBuyBtnVisible( false );        
87	
88	        // 鎖定方向
89	        Common.SetLockOrientation(true);
90	
91	        // 播放輪盤
92	        await this.PlayGoldBlitzRoulette();
93	
94	        // 播放免費遊戲音樂
95	        this.m_gameView.PlayFreeGameBgm();
96	
97	        // 準備進入免費遊戲
98	        newBottombarManager.SetBarNodeVisiable(true);
99	
100	        // 顯示免費遊戲回合數字
101	        eventManager.Dispatch(FREE_GAME_ROUND_UI_EVENT.SHOW);
102	
103	        // 開始Spin
104	        // 注意：EnterFreeState 進入時 CurPlateIndex 仍是 main game 的值，但要播的是 FreeGame round 1。
105	        // 顯式傳入 +1 偏移取得正確的 fileIndex（與 SetRealPlateInfo 用 CurPlateIndex+1 取資料的語意對齊）。
106	        // this.m_gameView.StartSpin(this.m_gameView.SlotReels.ResolveFakeReelFileIndex(1));
107	
108	        // 設定所有轉輪符號顯示模式為只顯示Blank
109	        this.m_gameView.SetAllReelSymbolMode( ReelSymbolMode.OnlyBlank );
110	        this.m_gameView.SetSlotReelCanPlaySymbolAudio( false );
111	
112	        // 初始化狀態標誌
113	        this.m_isMultiplierAnimFinish = false;
114	        this.m_isCashAnimFinish = false;
115	        this.m_phase = EnterFreeStatePhase.SPINNING;
116	
117	        // 播放免費遊戲加倍演出，完成後才開始現金演出
118	        void this.PlayFreeGameAddMultiplierAnim().then(() => {
119	            if ( !this.m_gameView?.node?.isValid ) return;
120	            this.m_isMultiplierAnimFinish = true;
121	
122	            // 倍率演出完成後，才開始現金演出
123	            void this.PlayFreeGameAddCashAnim().then(() => {
124	                if ( !this.m_gameView?.node?.isValid ) return;
125	                this.m_isCashAnimFinish = true;
126	            }).catch( e => console.warn( "[EnterFreeState] PlayFreeGameAddCashAnim error:", e ) );
127	        }).catch( e => console.warn( "[EnterFreeState] PlayFreeGameAddMultiplierAnim error:", e ) );
128	    }
129	
130	    public OnProcess( dt: number = 0 )
131	    {
132	        // 只有在 SPINNING 狀態才需要處理
133	        if ( this.m_phase !== EnterFreeStatePhase.SPINNING )
134	        {
135	            return;
136	        }
137	
138	        // 更新轉輪旋轉
139	        this.m_gameView.SlotReels.Spin( dt );
140	
141	        // 檢查演出是否全部完成
142	        if ( !this.m_isMultiplierAnimFinish || !this.m_isCashAnimFinish )
143	        {
144	            // 演出未完成，持續旋轉
145	            return;
146	        }
147	
148	        // 取消 FlyManager AddCash 延遲 callback（避免晚到 callback 在下一行 Normal 設定後把 col 改回 CashAndBlank）
149	        eventManager.Dispatch( FLY_EVENT.CANCEL_ADD_CASH_ANIMATION );
150	
151	        // 演出剛結束，切回 Normal 符號模式（BC-5；轉動中切換，1-frame 內可能有符號突現，Phase 4 dev preview 觀察重點）
152	        this.m_gameView.SetAllReelSymbolMode( ReelSymbolMode.Normal );
153	
154	        this.m_phase = EnterFreeStatePhase.COMPLETED;
155	
156	        // 處理 AutoSpin UI（移除原 SetSpinState(IDLE)，SpinState.OnEnter 會自行設 START_SPIN）
157	        if ( newBottombarManager.IsAutoSpin && this.m_gameView.AutoplayInfos.isCheckFree )
158	        {
159	            newBottombarManager.ShowAutoPlayState( false );
160	        }
161	
162	        // BC-2：統一設 IsFirstRound=false → RoundEndState.ForEndToNext 走 SPIN 分支（不再 IDLE 等點擊）
163	        this.m_gameView.IsFirstRound = false;
164	
165	        // BC-3：請 RoundEndState 跳過 0.5s noWin 緩衝（讀完即清，見 RoundEndState.OnEnter）
166	        this.m_gameView.SkipFreeGameNoWinDelay = true;
167	
168	        // BC-7：請 SpinState 對 SlotReels.StartSpin 傳 continueSpin=true（保留時間軸與 ColumnSymbol 視覺位置同步）
169	        this.m_gameView.IsFreeGameFirstSpinContinuous = true;
170	
171	        // 跳轉到下一個狀態
172	        stateManager.NextState( Game_Define.GameState.ROUND_END );
173	    }
174	
175	    public OnLeave()
176	    {
177	        this.m_gameView.SetAllReelSymbolMode( ReelSymbolMode.Normal );
178	        this.m_gameView.SetSlotReelCanPlaySymbolAudio( true );
179	
180	        eventManager.UnRegister( GOLD_BLITZ_ROULETTE_EVENT.ROTATE_COMPLETE, this );
181	
182	        // 重置狀態標誌
183	        this.m_phase = EnterFreeStatePhase.IDLE;
184	        this.m_isMultiplierAnimFinish = false;
185	        this.m_isCashAnimFinish = false;
186	        this.m_isPlayGoldBlitzRouletteFinish = false;
187	
188	        // 解除鎖定
189	        Common.SetLockOrientation(false);
190	    }
191	
192	    /**
193	     * @ch 停止效果
194	     */
195	    private StopEffect()
196	    {
197	        this.m_gameView.EffectPlate.StopOneLineShow();
198	        this.m_gameView.ClearAll();
199	        this.m_gameView.EffectPlate.CurAwardLines.length = 0;
200	    }
201	
202	    /**
203	     * @ch 事件處理
204	     * @param event 事件名稱
205	     * @param args 事件參數
206	     */
207	    OnEvent( event: string, ...args: any[] )
208	    {
209	        switch ( event ) {
210	            case GOLD_BLITZ_ROULETTE_EVENT.ROTATE_COMPLETE:
211	                this.m_isPlayGoldBlitzRouletteFinish = true;
212	                break;
213	        }
214	    }
215	
216	    /**
217	     * @ch 播放輪盤
218	     */
219	    async PlayGoldBlitzRoulette() : Promise<void>
220	    {
221	        log( "PlayGoldBlitzRoulette" );
222	
223	        if (!this.m_gameView.GoldBlitzRouletteWheelData || this.m_gameView.GoldBlitzRouletteWheelData.length <= 0) {
224	            error("[EnterFreeState] GoldBlitzRouletteWheelData is invalid");
225	            return;
226	        }
227	
228	        if (!this.m_gameView.RoundInfo) {
229	            error("[EnterFreeState] RoundInfo is invalid");
230	            return;
231	        }
232	
233	        // if (this.m_gameView.RoundInfo.FreeGameWheelIndex < 0 || this.m_gameView.RoundInfo.FreeGameWheelNumberIndex < 0) {
234	        //     error("[EnterFreeState] FreeGameWheelIndex or FreeGameWheelNumberIndex is invalid");
235	        //     return;
236	        // }
237	
238	        // // 設定輪盤資料
239	        // const wheelData = this.m_gameView.GetGoldBlitzRouletteWheelData(this.m_gameView.RoundInfo.FreeGameWheelIndex);
240	        // const stopIndex = this.m_gameView.RoundInfo.FreeGameWheelNumberIndex;
241	        // eventManager.Dispatch( GOLD_BLITZ_ROULETTE_EVENT.INIT, wheelData, stopIndex, this.m_gameView.RoundInfo.FreeMultiplierIndex );
242	
243	        // 初始化免費遊戲回合數字
244	        // eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.INIT, 0, wheelData[stopIndex] );
245	        // await Define.Wait( this.m_gameView, GOLD_BLITZ_ROULETTE_INIT_DELAY_SECONDS );
246	
247	        // 註冊輪盤播放完成事件
248	        eventManager.Register( GOLD_BLITZ_ROULETTE_EVENT.ROTATE_COMPLETE, this );
249	        this.m_isPlayGoldBlitzRouletteFinish = false;
250	
251	        // 隱藏其他 UI
252	        this.SetOhterUIShow(false, GOLD_BLITZ_ROULETTE_HIDE_OTHER_UI_DELAY_SECONDS);
253	
254	        // 顯示輪盤
255	        await this.PlayGoldBlitzRouletteInAnim();
256	
257	        // 等待輪盤Spin完成
258	        await WaitUntil(() => this.m_isPlayGoldBlitzRouletteFinish);
259	
260	        // 取消註冊輪盤播放完成事件
261	        eventManager.UnRegister( GOLD_BLITZ_ROULETTE_EVENT.ROTATE_COMPLETE, this );
262	
263	        // 顯示其他 UI
264	        this.SetOhterUIShow(true, GOLD_BLITZ_ROULETTE_SHOW_OTHER_UI_DELAY_SECONDS);
265	
266	        // 推入免費遊戲回合數字節點
267	        eventManager.Dispatch(MAGIC_POT_EVENT.PUSH_TO_FREE_GAME_NUMBER_ROOT_NODE);
268	
269	        // // 切換倍率UI
270	        // eventManager.Dispatch( MULTIPLIER_EVENT.SWITCH_ROULETTE_UI, MultiplierType.FreeGame );
271	
272	        // // 設置倍率
273	        // const multiplierIndex = this.m_gameView.RoundInfo.FreeMultiplierIndex;
274	        // eventManager.Dispatch(MULTIPLIER_EVENT.SET_INDEX, multiplierIndex, true);
275	
276	        // 更新背景
277	        this.m_gameView.CheckBackground();
278	
279	        // 隱藏輪盤
280	        await this.PlayGoldBlitzRouletteOutAnim();
281	    }
282	
283	    /**
284	     * @ch 設置其他 UI 顯示
285	     * @param isShow 是否顯示
