import { _decorator, error, log } from "cc";
import { stateManager, BaseState, newBottombarManager, eventManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define, { ReelSymbolMode } from "../Game_Define";
import { Define } from "db://astarte-framework/utilis";
import { GOLD_BLITZ_ROULETTE_EVENT } from "../FreeGame/GoldBlitzRoulette";
import { WaitUntil } from "../Common/AsyncUtils";
import { FREE_GAME_ROUND_UI_EVENT } from "../FreeGame/FreeGameRoundUI";
import { MULTIPLIER_EVENT, MultiplierType } from "../Multiplier/MultiplierManager";
import { SHOW_ADD_MULTIPLIER_EVENT } from "../Multiplier/ShowAddMultiplier";
import { FLY_EVENT } from "../FlyManager";
import { BLACK_MASK_EVENT } from "../BlackMaskManager";
import { REEL_MANAGER_EVENT } from "../ReelManager";
import { JP_EVENT } from "../JP/JP_Define";
import { BACKGROUND_UI_EVENT } from "../BackgroundManager";
import { Common } from "../Common/Common";
import { MAGIC_POT_EVENT } from "../MagicPot/MagicPotController";

const { ccclass } = _decorator;

// 進入免費遊戲狀態前的初始等待時間
const ENTER_FREE_INITIAL_DELAY_SECONDS = 1.5;

// 輪盤初始化後，開始後續流程前的等待時間
const GOLD_BLITZ_ROULETTE_INIT_DELAY_SECONDS = 0.5;

// 輪盤進場前，隱藏其他 UI 的延遲時間
const GOLD_BLITZ_ROULETTE_HIDE_OTHER_UI_DELAY_SECONDS = 0.5;

// 輪盤完成後，重新顯示其他 UI 的延遲時間
const GOLD_BLITZ_ROULETTE_SHOW_OTHER_UI_DELAY_SECONDS = 3;

// 現金飛分演出次數
const FREE_GAME_ADD_CASH_ANIMATION_COUNT = 15;

// 現金飛分演出的目標索引
const FREE_GAME_ADD_CASH_ANIMATION_TARGET_INDEXES = [0, 1, 2, 3, 4, 5];

// 現金飛分演出的每次間隔時間
const FREE_GAME_ADD_CASH_ANIMATION_INTERVAL_SECONDS = 0.1;

/**@ch EnterFreeState 狀態機階段*/
enum EnterFreeStatePhase {
    IDLE = 0,                      // 初始狀態
    SPINNING = 1,                  // 轉輪旋轉中，等待演出完成
    COMPLETED = 2                  // 轉輪停止，演出完成，準備跳轉
}

@ccclass( "EnterFreeState" )
export class EnterFreeState extends BaseState
{
    private m_gameView: GameView = null;

    /**@ch 是否播放輪盤完成*/
    private m_isPlayGoldBlitzRouletteFinish: boolean = false;

    /**@ch 當前狀態階段*/
    private m_phase: EnterFreeStatePhase = EnterFreeStatePhase.IDLE;

    /**@ch 倍率演出是否完成*/
    private m_isMultiplierAnimFinish: boolean = false;

    /**@ch 現金演出是否完成*/
    private m_isCashAnimFinish: boolean = false;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        log( "OnEnter State : ENTER_FREE" );

        await Define.Wait(this.m_gameView, ENTER_FREE_INITIAL_DELAY_SECONDS);

        // 暫停主遊戲背景音樂
        this.m_gameView.PauseMainGameBgm();

        newBottombarManager.SetEnterFree();
        this.StopEffect();
        this.m_gameView.IsFreeGame = true;

        newBottombarManager.SetBarNodeVisiable( false );
        this.m_gameView.BuyBonus?.SetBuyBtnVisible( false );        

        // 鎖定方向
        Common.SetLockOrientation(true);

        // 播放輪盤
        await this.PlayGoldBlitzRoulette();

        // 播放免費遊戲音樂
        this.m_gameView.PlayFreeGameBgm();

        // 準備進入免費遊戲
        newBottombarManager.SetBarNodeVisiable(true);

        // 顯示免費遊戲回合數字
        eventManager.Dispatch(FREE_GAME_ROUND_UI_EVENT.SHOW);

        // 開始Spin
        // 注意：EnterFreeState 進入時 CurPlateIndex 仍是 main game 的值，但要播的是 FreeGame round 1。
        // 顯式傳入 +1 偏移取得正確的 fileIndex（與 SetRealPlateInfo 用 CurPlateIndex+1 取資料的語意對齊）。
        // this.m_gameView.StartSpin(this.m_gameView.SlotReels.ResolveFakeReelFileIndex(1));

        // 設定所有轉輪符號顯示模式為只顯示Blank
        this.m_gameView.SetAllReelSymbolMode( ReelSymbolMode.OnlyBlank );
        this.m_gameView.SetSlotReelCanPlaySymbolAudio( false );

        // 初始化狀態標誌
        this.m_isMultiplierAnimFinish = false;
        this.m_isCashAnimFinish = false;
        this.m_phase = EnterFreeStatePhase.SPINNING;

        // 播放免費遊戲加倍演出，完成後才開始現金演出
        void this.PlayFreeGameAddMultiplierAnim().then(() => {
            if ( !this.m_gameView?.node?.isValid ) return;
            this.m_isMultiplierAnimFinish = true;

            // 倍率演出完成後，才開始現金演出
            void this.PlayFreeGameAddCashAnim().then(() => {
                if ( !this.m_gameView?.node?.isValid ) return;
                this.m_isCashAnimFinish = true;
            }).catch( e => console.warn( "[EnterFreeState] PlayFreeGameAddCashAnim error:", e ) );
        }).catch( e => console.warn( "[EnterFreeState] PlayFreeGameAddMultiplierAnim error:", e ) );
    }

    public OnProcess( dt: number = 0 )
    {
        // 只有在 SPINNING 狀態才需要處理
        if ( this.m_phase !== EnterFreeStatePhase.SPINNING )
        {
            return;
        }

        // 更新轉輪旋轉
        this.m_gameView.SlotReels.Spin( dt );

        // 檢查演出是否全部完成
        if ( !this.m_isMultiplierAnimFinish || !this.m_isCashAnimFinish )
        {
            // 演出未完成，持續旋轉
            return;
        }

        // 取消 FlyManager AddCash 延遲 callback（避免晚到 callback 在下一行 Normal 設定後把 col 改回 CashAndBlank）
        eventManager.Dispatch( FLY_EVENT.CANCEL_ADD_CASH_ANIMATION );

        // 演出剛結束，切回 Normal 符號模式（BC-5；轉動中切換，1-frame 內可能有符號突現，Phase 4 dev preview 觀察重點）
        this.m_gameView.SetAllReelSymbolMode( ReelSymbolMode.Normal );

        this.m_phase = EnterFreeStatePhase.COMPLETED;

        // 處理 AutoSpin UI（移除原 SetSpinState(IDLE)，SpinState.OnEnter 會自行設 START_SPIN）
        if ( newBottombarManager.IsAutoSpin && this.m_gameView.AutoplayInfos.isCheckFree )
        {
            newBottombarManager.ShowAutoPlayState( false );
        }

        // BC-2：統一設 IsFirstRound=false → RoundEndState.ForEndToNext 走 SPIN 分支（不再 IDLE 等點擊）
        this.m_gameView.IsFirstRound = false;

        // BC-3：請 RoundEndState 跳過 0.5s noWin 緩衝（讀完即清，見 RoundEndState.OnEnter）
        this.m_gameView.SkipFreeGameNoWinDelay = true;

        // BC-7：請 SpinState 對 SlotReels.StartSpin 傳 continueSpin=true（保留時間軸與 ColumnSymbol 視覺位置同步）
        this.m_gameView.IsFreeGameFirstSpinContinuous = true;

        // 跳轉到下一個狀態
        stateManager.NextState( Game_Define.GameState.ROUND_END );
    }

    public OnLeave()
    {
        this.m_gameView.SetAllReelSymbolMode( ReelSymbolMode.Normal );
        this.m_gameView.SetSlotReelCanPlaySymbolAudio( true );

        eventManager.UnRegister( GOLD_BLITZ_ROULETTE_EVENT.ROTATE_COMPLETE, this );

        // 重置狀態標誌
        this.m_phase = EnterFreeStatePhase.IDLE;
        this.m_isMultiplierAnimFinish = false;
        this.m_isCashAnimFinish = false;
        this.m_isPlayGoldBlitzRouletteFinish = false;

        // 解除鎖定
        Common.SetLockOrientation(false);
    }

    /**
     * @ch 停止效果
     */
    private StopEffect()
    {
        this.m_gameView.EffectPlate.StopOneLineShow();
        this.m_gameView.ClearAll();
        this.m_gameView.EffectPlate.CurAwardLines.length = 0;
    }

    /**
     * @ch 事件處理
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent( event: string, ...args: any[] )
    {
        switch ( event ) {
            case GOLD_BLITZ_ROULETTE_EVENT.ROTATE_COMPLETE:
                this.m_isPlayGoldBlitzRouletteFinish = true;
                break;
        }
    }

    /**
     * @ch 播放輪盤
     */
    async PlayGoldBlitzRoulette() : Promise<void>
    {
        log( "PlayGoldBlitzRoulette" );

        if (!this.m_gameView.GoldBlitzRouletteWheelData || this.m_gameView.GoldBlitzRouletteWheelData.length <= 0) {
            error("[EnterFreeState] GoldBlitzRouletteWheelData is invalid");
            return;
        }

        if (!this.m_gameView.RoundInfo) {
            error("[EnterFreeState] RoundInfo is invalid");
            return;
        }

        // if (this.m_gameView.RoundInfo.FreeGameWheelIndex < 0 || this.m_gameView.RoundInfo.FreeGameWheelNumberIndex < 0) {
        //     error("[EnterFreeState] FreeGameWheelIndex or FreeGameWheelNumberIndex is invalid");
        //     return;
        // }

        // // 設定輪盤資料
        // const wheelData = this.m_gameView.GetGoldBlitzRouletteWheelData(this.m_gameView.RoundInfo.FreeGameWheelIndex);
        // const stopIndex = this.m_gameView.RoundInfo.FreeGameWheelNumberIndex;
        // eventManager.Dispatch( GOLD_BLITZ_ROULETTE_EVENT.INIT, wheelData, stopIndex, this.m_gameView.RoundInfo.FreeMultiplierIndex );

        // 初始化免費遊戲回合數字
        // eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.INIT, 0, wheelData[stopIndex] );
        // await Define.Wait( this.m_gameView, GOLD_BLITZ_ROULETTE_INIT_DELAY_SECONDS );

        // 註冊輪盤播放完成事件
        eventManager.Register( GOLD_BLITZ_ROULETTE_EVENT.ROTATE_COMPLETE, this );
        this.m_isPlayGoldBlitzRouletteFinish = false;

        // 隱藏其他 UI
        this.SetOhterUIShow(false, GOLD_BLITZ_ROULETTE_HIDE_OTHER_UI_DELAY_SECONDS);

        // 顯示輪盤
        await this.PlayGoldBlitzRouletteInAnim();

        // 等待輪盤Spin完成
        await WaitUntil(() => this.m_isPlayGoldBlitzRouletteFinish);

        // 取消註冊輪盤播放完成事件
        eventManager.UnRegister( GOLD_BLITZ_ROULETTE_EVENT.ROTATE_COMPLETE, this );

        // 顯示其他 UI
        this.SetOhterUIShow(true, GOLD_BLITZ_ROULETTE_SHOW_OTHER_UI_DELAY_SECONDS);

        // 推入免費遊戲回合數字節點
        eventManager.Dispatch(MAGIC_POT_EVENT.PUSH_TO_FREE_GAME_NUMBER_ROOT_NODE);

        // // 切換倍率UI
        // eventManager.Dispatch( MULTIPLIER_EVENT.SWITCH_ROULETTE_UI, MultiplierType.FreeGame );

        // // 設置倍率
        // const multiplierIndex = this.m_gameView.RoundInfo.FreeMultiplierIndex;
        // eventManager.Dispatch(MULTIPLIER_EVENT.SET_INDEX, multiplierIndex, true);

        // 更新背景
        this.m_gameView.CheckBackground();

        // 隱藏輪盤
        await this.PlayGoldBlitzRouletteOutAnim();
    }

    /**
     * @ch 設置其他 UI 顯示
     * @param isShow 是否顯示
     * @param delay 延遲時間
     * @returns 
     */
    private async SetOhterUIShow(isShow: boolean, delay: number = 0) : Promise<void>
    {
        await Define.Wait(this.m_gameView, delay);
        if (isShow) {
            eventManager.Dispatch(BACKGROUND_UI_EVENT.SHOW_BACKGROUND);
            eventManager.Dispatch(REEL_MANAGER_EVENT.SHOW_UI);
            // eventManager.Dispatch(MULTIPLIER_EVENT.SHOW_UI);
            eventManager.Dispatch(JP_EVENT.SHOW_UI);
        } else {
            eventManager.Dispatch(BACKGROUND_UI_EVENT.HIDE_BACKGROUND);
            eventManager.Dispatch(REEL_MANAGER_EVENT.HIDE_UI);
            // eventManager.Dispatch(MULTIPLIER_EVENT.HIDE_UI);
            eventManager.Dispatch(JP_EVENT.HIDE_UI);
        }
    }

    /**
     * @ch 播放輪盤進場動畫
     * @returns 
     */
    private async PlayGoldBlitzRouletteInAnim() : Promise<void>
    {
        return new Promise<void>((resolve) => {
            eventManager.Dispatch(GOLD_BLITZ_ROULETTE_EVENT.PLAY_IN_ANIM, () => {
                resolve();
            });
        });
    }

    /**
     * @ch 播放輪盤退場動畫
     * @returns 
     */
    private async PlayGoldBlitzRouletteOutAnim() : Promise<void>
    {
        return new Promise<void>((resolve) => {
            eventManager.Dispatch(GOLD_BLITZ_ROULETTE_EVENT.PLAY_OUT_ANIM, () => {
                resolve();
            });
        });
    }

    /**
     * @ch 播放免費遊戲加倍演出
     * @returns 
     */
    private async PlayFreeGameAddMultiplierAnim() : Promise<void>
    {
        eventManager.Dispatch( BLACK_MASK_EVENT.SHOW_BLACK_MASK );
        await new Promise<void>((resolve) => {
            eventManager.Dispatch(SHOW_ADD_MULTIPLIER_EVENT.SHOW_ADD_MULTIPLIER, () => {
                resolve();
            });
        });
        eventManager.Dispatch( BLACK_MASK_EVENT.HIDE_BLACK_MASK );
    }

    /**
     * @ch 播放免費遊戲加現金演出
     * @returns
     */
    private async PlayFreeGameAddCashAnim() : Promise<void>
    {
        return new Promise<void>((resolve) => {
            eventManager.Dispatch(
                FLY_EVENT.PLAY_ADD_CASH_ANIMATION,
                FREE_GAME_ADD_CASH_ANIMATION_COUNT,
                FREE_GAME_ADD_CASH_ANIMATION_TARGET_INDEXES,
                FREE_GAME_ADD_CASH_ANIMATION_INTERVAL_SECONDS,
                () => {
                resolve();
                }
            );
        });
    }
}

