import { _decorator, log } from "cc";
import { BaseState, eventManager, newBottombarManager, stateManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import { Define } from "db://astarte-framework/utilis";
import { FREE_GAME_ROUND_UI_EVENT } from "../FreeGame/FreeGameRoundUI";
import { MULTIPLIER_EVENT, MultiplierType } from "../Multiplier/MultiplierManager";
import { MAGIC_POT_EVENT } from "../MagicPot/MagicPotController";
import { CachedGameData, GAME_DATA_CACHE_EVENT } from "../GameDataCache";
import { FREE_GAME_YOU_WIN_EVENT } from "../FreeGame/FreeGameYouWin";
import { Common } from "../Common/Common";

const { ccclass } = _decorator;


@ccclass( "LeaveFreeState" )
export class LeaveFreeState extends BaseState
{
    private m_gameView: GameView = null;

    /**
     * @ch 透過注入的 `GameView` 建立狀態實例
     * @param {GameView} gameView 遊戲主視圖引用
     */
    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    /**
     * @ch 進入狀態時呼叫，初始化離開免費遊戲的流程
     * @returns {Promise<void>}
     */
    public async OnEnter(): Promise<void>
    {
        log( "OnEnter State : LeaveFreeState" );
        this.LeaveFreeSetting();
    }

    /**
     * @ch 執行離開免費遊戲的設定流程（隱藏UI、停止BGM、播放提示動畫等）
     * @returns {Promise<void>}
     */
    async LeaveFreeSetting(): Promise<void>
    {
        newBottombarManager.SetBarNodeVisiable( false );

        // 等待2秒
        await Define.Wait(this.m_gameView, 2);

        // 停止免費遊戲BGM
        this.m_gameView.StopFreeGameBgm();

        newBottombarManager.SetLeaveFree();
        newBottombarManager.LockBetEnable( true );
        this.StopEffect(); // 請要停止的效果都放在這裡

        // ==================== 離開時的處理 ====================        
        // 設置主遊戲下注介面可見
        newBottombarManager.SetBarNodeVisiable( true );

        // 設置免費遊戲狀態為false
        this.m_gameView.IsFreeGame = false;

        // 鎖定方向
        Common.SetLockOrientation(true);

        // 播放你贏了動畫
        await this.PlayYouWonAnimation();

        // 播放MainGame BGM
        this.m_gameView.ResumeMainGameBgm();

        // NextState
        stateManager.NextState( Game_Define.GameState.ROUND_END );
        this.m_gameView.BuyBonus?.SetBuyBtnVisible( true );

        // 解除鎖定
        Common.SetLockOrientation(false);

        this.m_gameView.UpdateFakeReelBetMode()
    }

    /**
     * @ch 狀態更新循環（此狀態未使用）
     * @returns {void}
     */
    public OnProcess(): void
    {

    }

    /**
     * @ch 離開狀態時呼叫（此狀態未使用）
     * @returns {void}
     */
    public OnLeave(): void
    {

    }

    /**
     * @ch 停止效果
     * @returns {void}
     */
    private StopEffect(): void
    {
        this.m_gameView.EffectPlate.CurAwardLines.length = 0;
        this.m_gameView.EffectPlate.StopOneLineShow();
        this.m_gameView.ClearAll();
    }

    /**
     * @ch 恢復UI
     * @param {number} delay 延遲時間
     * @returns {void}
     */
    private async RestoreUI(delay: number = 0): Promise<void>
    {
        await Define.Wait(this.m_gameView, delay);
        eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.HIDE );

        const spinAck = this.m_gameView.SpinAck;
        // let multiplierIndex = spinAck.MultiplierIndex;
        let energyLevel = spinAck.ScAccuStage;

        // 檢查是否有Cache
        let isHasCache = false;
        eventManager.Dispatch( GAME_DATA_CACHE_EVENT.HAS_CACHE, (hasCache: boolean) => {
            isHasCache = hasCache;
        } );

        // 如果是在FeatureDemo時有Cache，則還原Cache資料
        if (this.m_gameView.IsAutoShowFeatures && isHasCache) {
            eventManager.Dispatch( GAME_DATA_CACHE_EVENT.LOAD_CACHE, (cache: CachedGameData) => {
                // multiplierIndex = cache.multiplierIndex;
                energyLevel = cache.energyLevel;
            } );
        }

        // // 切換倍率UI
        // eventManager.Dispatch( MULTIPLIER_EVENT.SWITCH_ROULETTE_UI, MultiplierType.MainGame );

        // 還原倍率
        // log( "還原倍率" );
        // eventManager.Dispatch( MULTIPLIER_EVENT.SET_INDEX, multiplierIndex, true );

        // 還原魔法罐等級
        log( "還原魔法罐等級" );
        eventManager.Dispatch( MAGIC_POT_EVENT.SET_LEVEL, energyLevel );

        // 檢查背景
        this.m_gameView.CheckBackground();
    }

    /**
     * @ch 播放你贏了動畫
     * @returns {Promise<void>}
     */
    private async PlayYouWonAnimation() : Promise<void>
    {
        // 設定不可轉向
        Common.SetLockOrientation( true );

        // 動畫開始播後0.1秒恢復 UI
        this.RestoreUI(7);

        // 播放完整的你贏了動畫（YouWonBoard 含進退場）
        const totalWin: number = this.m_gameView.SpinAck.TotalWin;
        const roundNumber: number = this.m_gameView.RoundInfo.FreeTotalRound ?? 0;
        await new Promise<void>((resolve) => {
            eventManager.Dispatch(FREE_GAME_YOU_WIN_EVENT.PLAY_ANIM, totalWin, roundNumber, () => resolve());
        });

        eventManager.Dispatch(MAGIC_POT_EVENT.POP_TO_FREE_GAME_NUMBER_ROOT_NODE);

        // 恢復旋轉
        Common.SetLockOrientation( false );
    }
}

