        await Define.Wait(this.m_gameView, delay);
        eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.HIDE );

        const spinAck = this.m_gameView.SpinAck;
        // let multiplierIndex = spinAck.MultiplierIndex;
        let energyLevel = spinAck.ScAccuStage;

        // 檢查是否有Cache
        let isHasCache = false;
        eventManager.Dispatch( GAME_DATA_CACHE_EVENT.HAS_CACHE, (hasCache: boolean) => {
            isHasCache = hasCache;
        } );

        // 如果是在FeatureDemo時有Cache，則還原Cache資料
        if (this.m_gameView.IsAutoShowFeatures && isHasCache) {
            eventManager.Dispatch( GAME_DATA_CACHE_EVENT.LOAD_CACHE, (cache: CachedGameData) => {
                // multiplierIndex = cache.multiplierIndex;
                energyLevel = cache.energyLevel;
            } );
        }

        // // 切換倍率UI
        // eventManager.Dispatch( MULTIPLIER_EVENT.SWITCH_ROULETTE_UI, MultiplierType.MainGame );

        // 還原倍率
        // log( "還原倍率" );
        // eventManager.Dispatch( MULTIPLIER_EVENT.SET_INDEX, multiplierIndex, true );

        // 還原魔法罐等級
        log( "還原魔法罐等級" );
        eventManager.Dispatch( MAGIC_POT_EVENT.SET_LEVEL, energyLevel );

        // 檢查背景
        this.m_gameView.CheckBackground();
    }

    /**
     * @ch 播放你贏了動畫
     * @returns {Promise<void>}
     */
    private async PlayYouWonAnimation() : Promise<void>
    {
        // 設定不可轉向
        Common.SetLockOrientation( true );

        // 動畫開始播後0.1秒恢復 UI
        this.RestoreUI(7);

        // 播放完整的你贏了動畫（YouWonBoard 含進退場）
        const totalWin: number = this.m_gameView.SpinAck.TotalWin;
        const roundNumber: number = this.m_gameView.RoundInfo.FreeTotalRound ?? 0;
        await new Promise<void>((resolve) => {
            eventManager.Dispatch(FREE_GAME_YOU_WIN_EVENT.PLAY_ANIM, totalWin, roundNumber, () => resolve());
        });

        eventManager.Dispatch(MAGIC_POT_EVENT.POP_TO_FREE_GAME_NUMBER_ROOT_NODE);

        // 恢復旋轉
        Common.SetLockOrientation( false );
    }
}

