import { _decorator, Component, Label } from "cc";
const { ccclass, property } = _decorator;

@ccclass( "SelectFrameController" )
export class SelectFrameController extends Component
{
    @property( {
        type: Label,
        tooltip: "框上的數字 Label（直接拖入，避免 getComponent 查找）"
    } )
    private m_label: Label = null;

    /**
     * @ch 設定框上顯示的文字
     * - 傳入空字串時隱藏 Label 節點
     */
    public SetText( text: string ): void
    {
        if ( !this.m_label )
        {
            return;
        }
        this.m_label.string = text;
        this.m_label.node.active = text.length > 0;
    }

    /**
     * @ch 清除文字並隱藏 Label（歸還 pool 前呼叫）
     */
    public Reset(): void
    {
        if ( !this.m_label )
        {
            return;
        }
        this.m_label.string = "";
        this.m_label.node.active = false;
    }
}

