public ShowSelectFrame( col: number, row: number, text: string = "", layer: number = Game_Define.LAYERS.ONE ): void
{
    this.HideSelectFrame( col, row );

    const worldPos = this.GetSymbolNodeWorldPos( col, row );

    if ( !this.m_selectFramePrefabs?.[ 0 ] )
    {
        console.warn( `[EffectPlate] ShowSelectFrame: m_selectFramePrefabs 未設定，無法建立選定框` );
        return;
    }

    const frameNode = BaseNodePool.getInstance().GetNode(
        Game_Define.EFFECT_TYPE.SELECT_FRAME,
        0,
    );
    frameNode.name = `SelectFrame_${col}_${row}`;

    this.m_effectNode[ layer ].addChild( frameNode );
    frameNode.setScale( v3( 1, 1, 1 ) );
    frameNode.setWorldPosition( worldPos );
    frameNode.active = true;
    tools.SetOrderedZindex( frameNode, col * 10 + row );

