import { _decorator, log } from "cc";
import GameView from "../GameView";
import { BaseState, eventManager, stateManager } from "db://astarte-framework/Managers";
import Game_Define from "../Game_Define";
import { FeatureWheelSegmentType } from "../FeatureWheel/FeatureWheelTypes";
import { FEATURE_MARK_EVENT } from "../FeatureWheel/FeatureMarkEvent";

const { ccclass } = _decorator;

/**
 * @ch Feature Wheel 後段結果演出 State（respin 全部結束後、結算前套用轉輪效果）
 *
 * 位置：respin 末手的 SCATTER_SHOW 之後、AWARD（結算）之前（由 GameView.AfterScatterToNext 守衛導向）。
 * 對應演出時序：⑦升級(Upgrade) → ⑦.5乘倍(Multiplier) → 交給 AWARD 做 ⑧結算（沿用）。
 *
 * 職責邊界：本 State 只負責「時機 + 順序 + 通知演出端」，實際升級/乘倍演出由同事 handler 渲染（seam）。
 *   - 升級在乘倍之前（用戶確認）。
 *   - 暫 fire-and-forget 派發（無 handler 不 hang）；待 handler 上線再視需要加 done callback 改 await 排序。
 */
@ccclass( "FeatureResultShowState" )
export class FeatureResultShowState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        log( "OnEnter State : FEATURE_RESULT_SHOW" );

        const round = this.m_gameView.RoundInfo;
        const upgradeResult = round?.UpgradeResult ?? [];
        const multiplierFeatures = ( round?.WheelFeatures ?? [] )
            .filter( w => w != null && w.Type === FeatureWheelSegmentType.Multiplier );

        // ⑦升級：先套用升級效果（CASH→Mystery）
        if ( upgradeResult.length > 0 )
        {
            eventManager.Dispatch( FEATURE_MARK_EVENT.APPLY_UPGRADE, upgradeResult );
        }

        // ⑦.5乘倍：升級後再套用乘倍（結算時乘上）
        if ( multiplierFeatures.length > 0 )
        {
            eventManager.Dispatch( FEATURE_MARK_EVENT.APPLY_MULTIPLIER, multiplierFeatures );
        }

        // ⑧結算：沿用 AWARD（讀 plate.Win）
        stateManager.NextState( Game_Define.GameState.AWARD );
    }

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }
}

